// ============ إعداد الجلسة ============
   session_start();
date_default_timezone_set('Asia/Gaza');
error_reporting(E_ALL);
ini_set('display_errors', 0);

// ============ إعدادات النظام ============
define('DB_PATH', __DIR__ . '/sohaibnet.sqlite');
define('ENCRYPTION_KEY', 'SohaibNet_SecureKey_2025_V18');
define('SYSTEM_VERSION', 'V22-SQLite');

$brandLogoDataUrl = 'data:image/jpeg;base64,';
function getSQLitePath(): string
{
    $path = defined('DB_PATH') ? DB_PATH : (__DIR__ . '/sohaibnet.sqlite');
    $dir = dirname($path);
    if (!is_dir($dir)) {
        @mkdir($dir, 0775, true);
    }
    return $path;
}

// ============ الاتصال بقاعدة البيانات ============
try {
    $pdo = new PDO('sqlite:' . getSQLitePath(), null, null, [
        PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
        PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
        PDO::ATTR_EMULATE_PREPARES => false,
    ]);
    $pdo->exec('PRAGMA foreign_keys = ON');
    $pdo->exec('PRAGMA journal_mode = WAL');
    $pdo->exec('PRAGMA synchronous = NORMAL');
} catch (PDOException $e) {
    die('❌ فشل الاتصال بقاعدة البيانات: ' . $e->getMessage());
}

// ============ إنشاء الجداول ============
function initDatabase(PDO $pdo): void
{
    $pdo->exec("CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        username TEXT NOT NULL UNIQUE,
        password TEXT NOT NULL,
        phone TEXT DEFAULT '',
        balance REAL DEFAULT 0,
        role TEXT NOT NULL DEFAULT 'user' CHECK(role IN ('admin','user')),
        is_blocked INTEGER NOT NULL DEFAULT 0,
        last_login_at TEXT DEFAULT NULL,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP,
        updated_at TEXT DEFAULT CURRENT_TIMESTAMP
    )");

    $pdo->exec("CREATE TABLE IF NOT EXISTS packages (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        title TEXT NOT NULL,
        price REAL NOT NULL DEFAULT 0,
        description TEXT DEFAULT '',
        icon TEXT DEFAULT 'fa-clock',
        color TEXT DEFAULT '#10b981',
        expiry_hours INTEGER DEFAULT 24,
        expiry_minutes INTEGER DEFAULT 0,
        is_active INTEGER DEFAULT 1,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP
    )");

    $pdo->exec("CREATE TABLE IF NOT EXISTS cards (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT NOT NULL UNIQUE,
        password TEXT NOT NULL,
        package_title TEXT DEFAULT 'بطاقة مخصصة',
        status TEXT NOT NULL DEFAULT 'متاح' CHECK(status IN ('متاح','مستعمل','منتهي')),
        owner TEXT DEFAULT 'admin',
        serial TEXT UNIQUE,
        validity_text TEXT DEFAULT '',
        price REAL DEFAULT 0,
        activated_at TEXT NULL,
        expiry_hours INTEGER DEFAULT 0,
        expiry_minutes INTEGER DEFAULT 0,
        custom_created INTEGER DEFAULT 0,
        active_session_id TEXT NULL,
        session_last_activity TEXT NULL,
        all_devices INTEGER DEFAULT 0,
        speed_mbps INTEGER DEFAULT 0,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP
    )");

    $pdo->exec("CREATE TABLE IF NOT EXISTS transactions (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_identifier TEXT NOT NULL,
        type TEXT DEFAULT 'system',
        title TEXT DEFAULT '',
        description TEXT DEFAULT '',
        amount REAL DEFAULT 0,
        transaction_date TEXT DEFAULT NULL,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP
    )");

    $pdo->exec("CREATE TABLE IF NOT EXISTS audit_logs (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        action TEXT DEFAULT '',
        details TEXT DEFAULT '',
        user TEXT DEFAULT 'نظام',
        ip_address TEXT DEFAULT '',
        created_at TEXT DEFAULT CURRENT_TIMESTAMP
    )");

    $pdo->exec("CREATE TABLE IF NOT EXISTS settings (
        setting_key TEXT PRIMARY KEY,
        setting_value TEXT DEFAULT '',
        updated_at TEXT DEFAULT CURRENT_TIMESTAMP
    )");

    $pdo->exec("CREATE TABLE IF NOT EXISTS device_sessions (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        card_username TEXT NOT NULL,
        device_id TEXT NOT NULL,
        ip_address TEXT DEFAULT '',
        last_activity TEXT DEFAULT CURRENT_TIMESTAMP,
        is_active INTEGER DEFAULT 1,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP,
        UNIQUE(card_username, device_id)
    )");

    $pdo->exec("CREATE TABLE IF NOT EXISTS devices_info (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        card_username TEXT NOT NULL,
        device_id TEXT NOT NULL,
        device_name TEXT DEFAULT '',
        mac_address TEXT DEFAULT '',
        last_seen TEXT DEFAULT CURRENT_TIMESTAMP,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP,
        UNIQUE(card_username, device_id)
    )");

    $pdo->exec("CREATE TABLE IF NOT EXISTS hotspot_settings (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        welcome_message TEXT DEFAULT '',
        marquee_text TEXT DEFAULT '',
        maintenance_mode INTEGER DEFAULT 0,
        updated_at TEXT DEFAULT CURRENT_TIMESTAMP
    )");

    $pdo->exec("CREATE INDEX IF NOT EXISTS idx_device_sessions_card ON device_sessions(card_username, device_id)");
    $pdo->exec("CREATE INDEX IF NOT EXISTS idx_devices_info_card ON devices_info(card_username, device_id)");
    $pdo->exec("CREATE INDEX IF NOT EXISTS idx_cards_owner ON cards(owner)");
    $pdo->exec("CREATE INDEX IF NOT EXISTS idx_cards_status ON cards(status)");

    $triggers = [
        "CREATE TRIGGER IF NOT EXISTS trg_users_updated_at AFTER UPDATE ON users
         FOR EACH ROW BEGIN
             UPDATE users SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;
         END",
        "CREATE TRIGGER IF NOT EXISTS trg_settings_updated_at AFTER UPDATE ON settings
         FOR EACH ROW BEGIN
             UPDATE settings SET updated_at = CURRENT_TIMESTAMP WHERE setting_key = NEW.setting_key;
         END",
        "CREATE TRIGGER IF NOT EXISTS trg_hotspot_settings_updated_at AFTER UPDATE ON hotspot_settings
         FOR EACH ROW BEGIN
             UPDATE hotspot_settings SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;
         END",
    ];
    foreach ($triggers as $sql) {
        try { $pdo->exec($sql); } catch (Exception $e) {}
    }

    try { $pdo->exec("ALTER TABLE cards ADD COLUMN all_devices INTEGER DEFAULT 0"); } catch (Exception $e) {}
    try { $pdo->exec("ALTER TABLE cards ADD COLUMN speed_mbps INTEGER DEFAULT 0"); } catch (Exception $e) {}
    try { $pdo->exec("ALTER TABLE cards ADD COLUMN active_session_id TEXT NULL"); } catch (Exception $e) {}
    try { $pdo->exec("ALTER TABLE cards ADD COLUMN session_last_activity TEXT NULL"); } catch (Exception $e) {}
    try { $pdo->exec("ALTER TABLE cards ADD COLUMN custom_created INTEGER DEFAULT 0"); } catch (Exception $e) {}
}

initDatabase($pdo);

// ============ دوال مساعدة ============
function encryptPassword($password)
{
    return hash('sha256', $password . 'SohaibNetSalt_2025');
}

function verifyPassword($input, $storedHash)
{
    if (strlen($storedHash) < 10) {
        return $input === $storedHash;
    }
    return encryptPassword($input) === $storedHash;
}

function generateSerial()
{
    return 'SN-' . strtoupper(substr(uniqid(), -6)) . rand(100, 999);
}

function getSetting(PDO $pdo, $key, $default = '')
{
    $stmt = $pdo->prepare("SELECT setting_value FROM settings WHERE setting_key = ?");
    $stmt->execute([$key]);
    $row = $stmt->fetch();
    return $row ? $row['setting_value'] : $default;
}

function saveSetting(PDO $pdo, $key, $value)
{
    $stmt = $pdo->prepare("INSERT INTO settings (setting_key, setting_value, updated_at)
        VALUES (?, ?, CURRENT_TIMESTAMP)
        ON CONFLICT(setting_key) DO UPDATE SET
            setting_value = excluded.setting_value,
            updated_at = CURRENT_TIMESTAMP");
    $stmt->execute([$key, $value]);
}

function addAuditLog(PDO $pdo, $action, $details = '', $user = 'نظام')
{
    $stmt = $pdo->prepare("INSERT INTO audit_logs (action, details, user, ip_address) VALUES (?, ?, ?, ?)");
    $stmt->execute([$action, $details, $user, $_SERVER['REMOTE_ADDR'] ?? '']);
    try {
        $pdo->exec("DELETE FROM audit_logs WHERE id NOT IN (SELECT id FROM (SELECT id FROM audit_logs ORDER BY id DESC LIMIT 500) tmp)");
    } catch (Exception $e) {}
}

function getClientIP()
{
    if (!empty($_SERVER['HTTP_CLIENT_IP'])) return $_SERVER['HTTP_CLIENT_IP'];
    if (!empty($_SERVER['HTTP_X_FORWARDED_FOR'])) return $_SERVER['HTTP_X_FORWARDED_FOR'];
    return $_SERVER['REMOTE_ADDR'] ?? '127.0.0.1';
}

function getCardExpiryTimestamp(array $card): ?int
{
    if (empty($card['activated_at'])) return null;
    $hours = intval($card['expiry_hours'] ?? 0);
    $minutes = intval($card['expiry_minutes'] ?? 0);
    $totalMinutes = ($hours * 60) + $minutes;
    if ($totalMinutes <= 0) return null;
    return strtotime($card['activated_at']) + ($totalMinutes * 60);
}

function cleanupExpiredCards(PDO $pdo): void
{
    $stmt = $pdo->query("SELECT id, activated_at, expiry_hours, expiry_minutes, status FROM cards WHERE activated_at IS NOT NULL");
    $now = time();
    foreach ($stmt->fetchAll() as $card) {
        $expiryTime = getCardExpiryTimestamp($card);
        if ($expiryTime && $now > $expiryTime && ($card['status'] ?? '') !== 'منتهي') {
            $up = $pdo->prepare("UPDATE cards SET status = 'منتهي', active_session_id = NULL, session_last_activity = NULL WHERE id = ?");
            $up->execute([$card['id']]);
        }
    }

    $stmt = $pdo->query("SELECT id, activated_at, expiry_hours, expiry_minutes FROM cards WHERE status = 'منتهي' AND activated_at IS NOT NULL");
    foreach ($stmt->fetchAll() as $card) {
        $expiryTime = getCardExpiryTimestamp($card);
        if ($expiryTime && $now > ($expiryTime + 86400)) {
            $pdo->prepare("DELETE FROM cards WHERE id = ?")->execute([$card['id']]);
        }
    }
}

