function ensureUserColumns(PDO $pdo): void
{
    try {
        $cols = [];
        $stmt = $pdo->query("PRAGMA table_info(users)");
        foreach ($stmt->fetchAll() as $row) {
            $cols[] = $row['name'];
        }
        if (!in_array('is_blocked', $cols, true)) {
            $pdo->exec("ALTER TABLE users ADD COLUMN is_blocked INTEGER NOT NULL DEFAULT 0");
        }
        if (!in_array('last_login_at', $cols, true)) {
            $pdo->exec("ALTER TABLE users ADD COLUMN last_login_at TEXT DEFAULT NULL");
        }
    } catch (Throwable $e) {
        // تجاهل أخطاء الترحيل حتى لا يتوقف النظام
    }
}

ensureUserColumns($pdo);

ensureDefaultData($pdo);

// ============ معالجة طلبات AJAX ============
if (isset($_GET['action']) || isset($_POST['action'])) {
    header('Content-Type: application/json; charset=utf-8');
    $action = $_GET['action'] ?? $_POST['action'] ?? '';

    function jsonResponse($data, $status = 200)
    {
        http_response_code($status);
        echo json_encode($data, JSON_UNESCAPED_UNICODE);
        exit;
    }

    // ============ الاتصال بالإنترنت (Hot Spot) ============
    if ($action === 'connect_wifi') {
        $username = trim($_POST['username'] ?? '');
        $password = trim($_POST['password'] ?? '');
        $deviceId = trim($_POST['device_id'] ?? '');
        $deviceName = trim($_POST['device_name'] ?? '');
        $macAddress = trim($_POST['mac_address'] ?? '');

        if (empty($username) || empty($password)) {
            jsonResponse(['success' => false, 'message' => 'الرجاء إدخال اسم المستخدم وكلمة المرور معاً'], 400);
        }

        $stmt = $pdo->prepare("SELECT * FROM cards WHERE username = ? AND password = ?");
        $stmt->execute([$username, $password]);
        $card = $stmt->fetch();

        if (!$card) {
            jsonResponse(['success' => false, 'message' => '. تأكد من صحة اسم المستخدم وكلمة المرور وحاول مجدداً.'], 404);
        }

        // إذا كانت البطاقة تسمح لجميع الأجهزة
        if ($card['all_devices'] != 1) {
            $stmt = $pdo->prepare("SELECT * FROM device_sessions WHERE card_username = ? AND is_active = 1 AND device_id != ? AND last_activity > datetime('now', '-2 minutes')");
            $stmt->execute([$username, $deviceId]);
            $activeSession = $stmt->fetch();

            if ($activeSession) {
                jsonResponse([
                    'success' => false,
                    'message' => '⚠️ يتعذر تسجيل الدخول، فالبطاقة قيد الاستخدام على جهازٍ آخر.',
                    'session_conflict' => true
                ], 409);
            }
        }

        // رفض البطاقات المنتهية أو المحظورة
        if (($card['status'] ?? '') === 'منتهي') {
            addAuditLog($pdo, 'محاولة دخول ببطاقة منتهية', "يوزر: $username", $username);
            jsonResponse([
                'success' => false,
                'message' => '⚠️ عذراً، انتهت صلاحية هذه البطاقة.',
                'expired' => true
            ], 410);
        }

        // تفعيل البطاقة إذا كانت متاحة
        if ($card['status'] === 'متاح') {
            $stmt = $pdo->prepare("UPDATE cards SET status = 'مستعمل', activated_at = CURRENT_TIMESTAMP WHERE id = ?");
            $stmt->execute([$card['id']]);
            $card['status'] = 'مستعمل';
            $card['activated_at'] = date('Y-m-d H:i:s');
        }

        // التحقق من انتهاء الصلاحية
        if ($card['activated_at'] && ($card['expiry_hours'] > 0 || $card['expiry_minutes'] > 0)) {
            $expiryTime = getCardExpiryTimestamp($card);
            if ($expiryTime && time() > $expiryTime) {
                $stmt = $pdo->prepare("UPDATE cards SET status = 'منتهي', active_session_id = NULL, session_last_activity = NULL WHERE id = ?");
                $stmt->execute([$card['id']]);

                jsonResponse([
                    'success' => false,
                    'message' => '⚠️ عذراً، انتهت صلاحية هذه البطاقة.".',
                    'expired' => true
                ], 410);
            }
        }

        // تسجيل جلسة الجهاز
        $stmt = $pdo->prepare("INSERT INTO device_sessions (card_username, device_id, ip_address, last_activity, is_active) VALUES (?, ?, ?, CURRENT_TIMESTAMP, 1)
            ON CONFLICT(card_username, device_id) DO UPDATE SET
                ip_address = excluded.ip_address,
                last_activity = CURRENT_TIMESTAMP,
                is_active = 1");
        $stmt->execute([$username, $deviceId, getClientIP()]);

        // حفظ معلومات الجهاز
        if (!empty($deviceName) || !empty($macAddress)) {
            $stmt = $pdo->prepare("INSERT INTO devices_info (card_username, device_id, device_name, mac_address, last_seen) VALUES (?, ?, ?, ?, CURRENT_TIMESTAMP)
                ON CONFLICT(card_username, device_id) DO UPDATE SET
                    device_name = excluded.device_name,
                    mac_address = excluded.mac_address,
                    last_seen = CURRENT_TIMESTAMP");
            $stmt->execute([$username, $deviceId, $deviceName, $macAddress]);
        }

        $stmt = $pdo->prepare("UPDATE cards SET active_session_id = ?, session_last_activity = CURRENT_TIMESTAMP WHERE username = ?");
        $stmt->execute([$deviceId, $username]);

        addAuditLog($pdo, 'اتصال بالإنترنت', "يوزر: $username | الجهاز: $deviceName ($deviceId)", $username);

        jsonResponse([
            'success' => true,
            'message' => 'تم الاتصال بالشبكة بنجاح، نتمنى لكم تجربة استخدام ممتعة 🎉',
            'card' => [
                'username' => $card['username'],
                'password' => $card['password'],
                'package_title' => $card['package_title'],
                'validity_text' => $card['validity_text'],
                'serial' => $card['serial'],
                'price' => $card['price'],
                'activated_at' => $card['activated_at'],
                'expiry_hours' => $card['expiry_hours'],
                'expiry_minutes' => $card['expiry_minutes'],
            ],
            'device_name' => $deviceName,
            'mac_address' => $macAddress
        ]);
    }

    // ============ تسجيل الخروج من Hot Spot ============
    if ($action === 'disconnect_wifi') {
        $username = trim($_POST['username'] ?? '');
        $deviceId = trim($_POST['device_id'] ?? '');

        $stmt = $pdo->prepare("UPDATE device_sessions SET is_active = 0 WHERE card_username = ? AND device_id = ?");
        $stmt->execute([$username, $deviceId]);

        $stmt = $pdo->prepare("UPDATE cards SET active_session_id = NULL, session_last_activity = NULL WHERE username = ?");
        $stmt->execute([$username]);

        addAuditLog($pdo, 'تسجيل خروج Hot Spot', "يوزر: $username", $username);
        jsonResponse(['success' => true, 'message' => 'تم تسجيل الخروج بنجاح.']);
    }

    // ============ تسجيل دخول المتجر ============
    if ($action === 'login_store') {
        $username = trim(strtolower($_POST['username'] ?? ''));
        $password = trim($_POST['password'] ?? '');

        $stmt = $pdo->prepare("SELECT * FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch();

        if (!$user || !verifyPassword($password, $user['password'])) {
            addAuditLog($pdo, 'محاولة دخول فاشلة', "يوزر: $username", $username);
            jsonResponse(['success' => false, 'message' => 'بيانات الدخول غير صحيحة. تأكد من اسم المستخدم وكلمة المرور.'], 401);
        }

        if ((int)($user['is_blocked'] ?? 0) === 1) {
            addAuditLog($pdo, 'محاولة دخول لمستخدم محظور', "المستخدم: {$user['username']}", $user['username']);
            jsonResponse(['success' => false, 'message' => 'تم حظر هذا الحساب من الإدارة.'], 403);
        }

        $pdo->prepare("UPDATE users SET last_login_at = CURRENT_TIMESTAMP WHERE username = ?")->execute([$user['username']]);
        $stmt = $pdo->prepare("SELECT * FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch();

        $_SESSION['store_user'] = $user;
        addAuditLog($pdo, 'تسجيل دخول', "المستخدم: {$user['name']} ({$user['username']})", $user['username']);
        jsonResponse(['success' => true, 'user' => ['name' => $user['name'], 'username' => $user['username'], 'role' => $user['role'], 'balance' => $user['balance'], 'phone' => $user['phone']]]);
    }

    // ============ تسجيل حساب جديد ============
    if ($action === 'register_store') {
        $name = trim($_POST['name'] ?? '');
        $username = trim(strtolower($_POST['username'] ?? ''));
        $phone = trim($_POST['phone'] ?? '');
        $password = trim($_POST['password'] ?? '');
        $passwordConfirm = trim($_POST['password_confirm'] ?? '');

        if (empty($name) || empty($username) || empty($phone) || empty($password)) {
            jsonResponse(['success' => false, 'message' => 'الرجاء ملء جميع الحقول المطلوبة'], 400);
        }
        if ($password !== $passwordConfirm) {
            jsonResponse(['success' => false, 'message' => 'كلمتا المرور غير متطابقتين.'], 400);
        }
        if (strlen($password) < 3) {
            jsonResponse(['success' => false, 'message' => 'كلمة المرور يجب أن تكون 3 أحرف على الأقل.'], 400);
        }

        $stmt = $pdo->prepare("SELECT COUNT(*) FROM users WHERE username = ?");
        $stmt->execute([$username]);
        if ($stmt->fetchColumn() > 0) {
            jsonResponse(['success' => false, 'message' => 'اسم المستخدم موجود مسبقاً.'], 409);
        }

        $stmt = $pdo->prepare("INSERT INTO users (name, username, password, phone, balance, role) VALUES (?, ?, ?, ?, 0, 'user')");
        $stmt->execute([$name, $username, encryptPassword($password), $phone]);

        addAuditLog($pdo, 'تسجيل مستخدم جديد', "الاسم: $name | اليوزر: $username", $username);
        jsonResponse(['success' => true, 'message' => 'تم إنشاء الحساب بنجاح. يمكنك الآن تسجيل الدخول.']);
    }

    // ============ شراء بطاقة ============
    if ($action === 'buy_card') {
        if (!isset($_SESSION['store_user'])) {
            jsonResponse(['success' => false, 'message' => 'يرجى تسجيل الدخول أولاً'], 401);
        }

        $sessionUser = $_SESSION['store_user'];
        $packageId = intval($_POST['package_id'] ?? 0);

        try {
            if (!$pdo->inTransaction()) {
                $pdo->beginTransaction();
            }

            $stmt = $pdo->prepare("SELECT id, name, username, balance, role FROM users WHERE id = ? LIMIT 1");
            $stmt->execute([$sessionUser['id']]);
            $user = $stmt->fetch();

            if (!$user) {
                if ($pdo->inTransaction()) $pdo->rollBack();
                jsonResponse(['success' => false, 'message' => 'المستخدم غير موجود'], 404);
            }

            $stmt = $pdo->prepare("SELECT * FROM packages WHERE id = ? AND is_active = 1");
            $stmt->execute([$packageId]);
            $package = $stmt->fetch();

            if (!$package) {
                if ($pdo->inTransaction()) $pdo->rollBack();
                jsonResponse(['success' => false, 'message' => 'الباقة غير موجودة'], 404);
            }

            if ((float)$user['balance'] < (float)$package['price']) {
                if ($pdo->inTransaction()) $pdo->rollBack();
                jsonResponse(['success' => false, 'message' => "رصيدك غير كافٍ. الرصيد: {$user['balance']} ₪ | السعر: {$package['price']} ₪"], 400);
            }

            $stmt = $pdo->prepare("SELECT * FROM cards WHERE package_title = ? AND status = 'متاح' AND owner = 'admin' LIMIT 1");
            $stmt->execute([$package['title']]);
            $stockCard = $stmt->fetch();

            if (!$stockCard) {
                if ($pdo->inTransaction()) $pdo->rollBack();
                jsonResponse(['success' => false, 'message' => '⚠️ نفدت الكروت المتاحة لهذه الباقة.'], 404);
            }

            $stmt = $pdo->prepare("UPDATE users SET balance = balance - ? WHERE id = ?");
            $stmt->execute([$package['price'], $user['id']]);

            $stmt = $pdo->prepare("UPDATE cards SET status = 'مستعمل', owner = ?, activated_at = CURRENT_TIMESTAMP, expiry_hours = ?, expiry_minutes = ? WHERE id = ? AND status = 'متاح'");
            $stmt->execute([$user['username'], $package['expiry_hours'], $package['expiry_minutes'], $stockCard['id']]);

            if ($stmt->rowCount() < 1) {
                if ($pdo->inTransaction()) $pdo->rollBack();
                jsonResponse(['success' => false, 'message' => 'تم حجز البطاقة من مستخدم آخر في نفس اللحظة. حاول مرة أخرى.'], 409);
            }

            $stmt = $pdo->prepare("INSERT INTO transactions (user_identifier, type, title, description, amount, transaction_date) VALUES (?, 'buy', ?, ?, ?, date('now'))");
            $stmt->execute([$user['username'], 'شراء ' . $package['title'], 'يوزر: ' . $stockCard['username'], -$package['price']]);

            $stmt = $pdo->prepare("SELECT balance FROM users WHERE id = ?");
            $stmt->execute([$user['id']]);
            $freshBalance = $stmt->fetchColumn();

            addAuditLog($pdo, 'شراء بطاقة', "المستخدم: {$user['username']} | باقة: {$package['title']}", $user['username']);

            if ($pdo->inTransaction()) {
                $pdo->commit();
            }

            $_SESSION['store_user'] = array_merge($sessionUser, [
                'balance' => $freshBalance,
                'username' => $user['username'],
                'name' => $user['name']
            ]);

            jsonResponse([
                'success' => true,
                'message' => '"تم شراء البطاقة بنجاح، ويمكنكم استخدامها الآن."! 🎉',
                'card' => [
                    'username' => $stockCard['username'],
                    'password' => $stockCard['password'],
                    'package_title' => $stockCard['package_title'],
                ],
                'new_balance' => $freshBalance
            ]);
        } catch (Throwable $e) {
            if ($pdo->inTransaction()) {
                $pdo->rollBack();
            }
            jsonResponse(['success' => false, 'message' => 'فشل تنفيذ عملية الشراء: ' . $e->getMessage()], 500);
        }
    }

    // ============ الحصول على بيانات المتجر ============
    if ($action === 'get_store_data') {
        if (!isset($_SESSION['store_user'])) {
            jsonResponse(['success' => false, 'message' => 'يرجى تسجيل الدخول'], 401);
        }
        $user = $_SESSION['store_user'];

        cleanupExpiredCards($pdo);

        $packages = $pdo->query("SELECT * FROM packages WHERE is_active = 1")->fetchAll();
        $packagesWithStock = [];
        foreach ($packages as $pkg) {
            $stmt = $pdo->prepare("SELECT COUNT(*) FROM cards WHERE package_title = ? AND status = 'متاح'");
            $stmt->execute([$pkg['title']]);
            $pkg['stock_count'] = $stmt->fetchColumn();
            $packagesWithStock[] = $pkg;
        }

        $stmt = $pdo->prepare("SELECT * FROM transactions WHERE user_identifier = ? OR user_identifier = ? ORDER BY id DESC LIMIT 50");
        $stmt->execute([$user['username'], $user['name']]);
        $transactions = $stmt->fetchAll();

        $stmt = $pdo->prepare("SELECT * FROM cards WHERE owner = ? ORDER BY id DESC");
        $stmt->execute([$user['username']]);
        $myCards = $stmt->fetchAll();

        jsonResponse([
            'success' => true,
            'user' => $user,
            'packages' => $packagesWithStock,
            'transactions' => $transactions,
            'my_cards' => $myCards
        ]);
    }

    // ============ إرسال رصيد ============
    if ($action === 'send_balance') {
        if (!isset($_SESSION['store_user'])) {
            jsonResponse(['success' => false, 'message' => 'يرجى تسجيل الدخول'], 401);
        }
        $sender = $_SESSION['store_user'];
        $phone = trim($_POST['phone'] ?? '');
        $amount = floatval($_POST['amount'] ?? 0);

        if (empty($phone) || $amount <= 0) {
            jsonResponse(['success' => false, 'message' => 'بيانات غير صحيحة'], 400);
        }

        $stmt = $pdo->prepare("SELECT * FROM users WHERE phone = ? AND username != ?");
        $stmt->execute([$phone, $sender['username']]);
        $receiver = $stmt->fetch();

        if (!$receiver) {
            jsonResponse(['success' => false, 'message' => 'المستلم غير مسجل في النظام'], 404);
        }
        if ($sender['balance'] < $amount) {
            jsonResponse(['success' => false, 'message' => 'رصيدك غير كافٍ'], 400);
        }

        $pdo->beginTransaction();
        try {
            $stmt = $pdo->prepare("UPDATE users SET balance = balance - ? WHERE id = ?");
            $stmt->execute([$amount, $sender['id']]);
            $stmt = $pdo->prepare("UPDATE users SET balance = balance + ? WHERE id = ?");
            $stmt->execute([$amount, $receiver['id']]);

            $stmt = $pdo->prepare("INSERT INTO transactions (user_identifier, type, title, description, amount, transaction_date) VALUES (?, 'send', ?, ?, ?, date('now'))");
            $stmt->execute([$sender['username'], 'تحويل إلى ' . $receiver['name'], 'صادر', -$amount]);
            $stmt->execute([$receiver['username'], 'استلام من ' . $sender['name'], 'وارد', $amount]);

            $pdo->commit();
            $_SESSION['store_user']['balance'] = $sender['balance'] - $amount;
            addAuditLog($pdo, 'تحويل رصيد', "من: {$sender['username']} | إلى: {$receiver['username']} | مبلغ: $amount", $sender['username']);

            $invoiceNo = 'INV-' . date('YmdHis') . '-' . random_int(100, 999);
            jsonResponse([
                'success' => true,
                'message' => "تم تحويل $amount ₪ إلى {$receiver['name']}",
                'new_balance' => $sender['balance'] - $amount,
                'invoice' => [
                    'invoice_no' => $invoiceNo,
                    'sender_name' => $sender['name'],
                    'sender_username' => $sender['username'],
                    'receiver_name' => $receiver['name'],
                    'receiver_username' => $receiver['username'],
                    'receiver_phone' => $receiver['phone'],
                    'amount' => $amount,
                    'date' => date('Y-m-d H:i:s')
                ]
            ]);
        } catch (Exception $e) {
            $pdo->rollBack();
            jsonResponse(['success' => false, 'message' => 'حدث خطأ في العملية'], 500);
        }
    }

    // ============ التحقق من المستلم قبل التحويل ============
    if ($action === 'lookup_user_by_phone') {
        if (!isset($_SESSION['store_user'])) {
            jsonResponse(['success' => false, 'message' => 'يرجى تسجيل الدخول'], 401);
        }
        $phone = trim($_POST['phone'] ?? '');
        if (empty($phone)) {
            jsonResponse(['success' => false, 'message' => 'الرجاء إدخال رقم الهاتف'], 400);
        }
        $stmt = $pdo->prepare("SELECT name, username, phone, balance FROM users WHERE phone = ? AND username != ?");
        $stmt->execute([$phone, $_SESSION['store_user']['username']]);
        $user = $stmt->fetch();
        if (!$user) {
            jsonResponse(['success' => false, 'message' => 'المستلم غير مسجل في النظام'], 404);
        }
        jsonResponse(['success' => true, 'user' => $user]);
    }

    // ============ سحب بطاقة من مستخدم ============
    if ($action === 'withdraw_user_card') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $username = trim($_POST['username'] ?? '');
        if (empty($username)) {
            jsonResponse(['success' => false, 'message' => 'الرجاء تحديد المستخدم'], 400);
        }

        $stmt = $pdo->prepare("SELECT * FROM cards WHERE username = ? ORDER BY id DESC LIMIT 1");
        $stmt->execute([$username]);
        $card = $stmt->fetch();
        if (!$card) {
            jsonResponse(['success' => false, 'message' => 'لم يتم العثور على بطاقة للمستخدم'], 404);
        }

        $pdo->beginTransaction();
        try {
            $stmt = $pdo->prepare("UPDATE cards SET status = 'متاح', owner = 'admin', activated_at = NULL, active_session_id = NULL, session_last_activity = NULL, all_devices = COALESCE(all_devices,0) WHERE id = ?");
            $stmt->execute([$card['id']]);
            $stmt = $pdo->prepare("UPDATE device_sessions SET is_active = 0 WHERE card_username = ?");
            $stmt->execute([$username]);
            $stmt = $pdo->prepare("DELETE FROM devices_info WHERE card_username = ?");
            $stmt->execute([$username]);
            addAuditLog($pdo, 'سحب بطاقة', "المستخدم: $username | البطاقة: {$card['username']}", $_SESSION['store_user']['username']);
            $pdo->commit();
            jsonResponse(['success' => true, 'message' => 'تم سحب البطاقة وإعادتها للمخزن']);
        } catch (Exception $e) {
            $pdo->rollBack();
            jsonResponse(['success' => false, 'message' => 'حدث خطأ أثناء سحب البطاقة'], 500);
        }
    }

    // ============ بيانات لوحة الإدارة ============
    if ($action === 'get_admin_data') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }

        $usersCount = $pdo->query("SELECT COUNT(*) FROM users")->fetchColumn();
        $cardsCount = $pdo->query("SELECT COUNT(*) FROM cards")->fetchColumn();
        $totalMoney = $pdo->query("SELECT COALESCE(SUM(balance), 0) FROM users")->fetchColumn();
        $users = $pdo->query("SELECT * FROM users ORDER BY id DESC")->fetchAll();
        $cards = $pdo->query("SELECT * FROM cards ORDER BY id DESC")->fetchAll();
        $packages = $pdo->query("SELECT * FROM packages ORDER BY id ASC")->fetchAll();
        $transactions = $pdo->query("SELECT * FROM transactions ORDER BY id DESC LIMIT 100")->fetchAll();
        $auditLogs = $pdo->query("SELECT * FROM audit_logs ORDER BY id DESC LIMIT 100")->fetchAll();
        $liveSessions = $pdo->query("SELECT ds.*, c.package_title, c.status, c.expiry_hours, c.expiry_minutes, c.serial
            FROM device_sessions ds
            LEFT JOIN cards c ON c.username = ds.card_username
            WHERE ds.is_active = 1
            ORDER BY ds.last_activity DESC")->fetchAll();
        $settings = $pdo->query("SELECT * FROM settings")->fetchAll();
        $settingsAssoc = [];
        foreach ($settings as $s) {
            $settingsAssoc[$s['setting_key']] = $s['setting_value'];
        }
        
        $hotspotSettings = [];
        $hs = $pdo->query("SELECT * FROM hotspot_settings ORDER BY id DESC LIMIT 1")->fetch();
        if ($hs) {
            $hotspotSettings = $hs;
        }

        jsonResponse([
            'success' => true,
            'stats' => ['users' => $usersCount, 'cards' => $cardsCount, 'total_money' => $totalMoney],
            'users' => $users,
            'cards' => $cards,
            'packages' => $packages,
            'transactions' => $transactions,
            'audit_logs' => $auditLogs,
            'live_sessions' => $liveSessions,
            'settings' => $settingsAssoc,
            'hotspot_settings' => $hotspotSettings
        ]);
    }

    // ============ الجلسات الحية ============
    if ($action === 'get_live_sessions') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $sessions = $pdo->query("SELECT ds.*, c.package_title, c.status, c.expiry_hours, c.expiry_minutes
            FROM device_sessions ds
            LEFT JOIN cards c ON c.username = ds.card_username
            WHERE ds.is_active = 1
            ORDER BY ds.last_activity DESC")->fetchAll();
        jsonResponse(['success' => true, 'sessions' => $sessions]);
    }

    if ($action === 'kick_session') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $username = trim($_POST['username'] ?? '');
        $deviceId = trim($_POST['device_id'] ?? '');
        if ($username === '' || $deviceId === '') {
            jsonResponse(['success' => false, 'message' => 'بيانات غير مكتملة'], 400);
        }
        $stmt = $pdo->prepare("UPDATE device_sessions SET is_active = 0 WHERE card_username = ? AND device_id = ?");
        $stmt->execute([$username, $deviceId]);
        $stmt = $pdo->prepare("UPDATE cards SET active_session_id = NULL, session_last_activity = NULL WHERE username = ?");
        $stmt->execute([$username]);
        addAuditLog($pdo, 'طرد جلسة', "يوزر: $username | جهاز: $deviceId", $_SESSION['store_user']['username']);
        jsonResponse(['success' => true, 'message' => 'تم إنهاء الجلسة']);
    }

    // ============ حفظ الإعدادات ============
    if ($action === 'save_settings') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $settings = $_POST['settings'] ?? [];
        foreach ($settings as $key => $value) {
            saveSetting($pdo, $key, $value);
        }
        addAuditLog($pdo, 'تحديث الإعدادات', '', $_SESSION['store_user']['username']);
        jsonResponse(['success' => true, 'message' => 'تم حفظ الإعدادات']);
    }

    // ============ حفظ إعدادات Hot Spot ============
    if ($action === 'save_hotspot_settings') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $welcomeMsg = $_POST['welcome_message'] ?? '';
        $marqueeText = $_POST['marquee_text'] ?? '';
        $maintenance = intval($_POST['maintenance_mode'] ?? 0);
        
        $stmt = $pdo->prepare("INSERT INTO hotspot_settings (welcome_message, marquee_text, maintenance_mode) VALUES (?, ?, ?)");
        $stmt->execute([$welcomeMsg, $marqueeText, $maintenance]);
        
        saveSetting($pdo, 'marquee_text', $marqueeText);
        saveSetting($pdo, 'welcome_message', $welcomeMsg);
        
        addAuditLog($pdo, 'تحديث إعدادات Hot Spot', '', $_SESSION['store_user']['username']);
        jsonResponse(['success' => true, 'message' => 'تم حفظ إعدادات Hot Spot']);
    }

    // ============ إضافة/تعديل باقة ============
    if ($action === 'save_package') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $id = $_POST['id'] ?? null;
        $data = [
            'title' => $_POST['title'] ?? '',
            'price' => floatval($_POST['price'] ?? 0),
            'description' => $_POST['description'] ?? '',
            'icon' => $_POST['icon'] ?? 'fa-clock',
            'color' => $_POST['color'] ?? '#10b981',
            'expiry_hours' => intval($_POST['expiry_hours'] ?? 24),
            'expiry_minutes' => intval($_POST['expiry_minutes'] ?? 0),
        ];

        if ($id) {
            $stmt = $pdo->prepare("UPDATE packages SET title=?, price=?, description=?, icon=?, color=?, expiry_hours=?, expiry_minutes=? WHERE id=?");
            $stmt->execute([$data['title'], $data['price'], $data['description'], $data['icon'], $data['color'], $data['expiry_hours'], $data['expiry_minutes'], $id]);
        } else {
            $stmt = $pdo->prepare("INSERT INTO packages (title, price, description, icon, color, expiry_hours, expiry_minutes) VALUES (?,?,?,?,?,?,?)");
            $stmt->execute([$data['title'], $data['price'], $data['description'], $data['icon'], $data['color'], $data['expiry_hours'], $data['expiry_minutes']]);
        }
        addAuditLog($pdo, $id ? 'تعديل باقة' : 'إضافة باقة', "الباقة: {$data['title']}", $_SESSION['store_user']['username']);
        jsonResponse(['success' => true, 'message' => 'تم حفظ الباقة']);
    }

    // ============ حذف باقة ============
    if ($action === 'delete_package') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $id = intval($_POST['id'] ?? 0);
        $stmt = $pdo->prepare("SELECT title FROM packages WHERE id = ?");
        $stmt->execute([$id]);
        $pkg = $stmt->fetch();
        if ($pkg) {
            $pdo->prepare("DELETE FROM packages WHERE id = ?")->execute([$id]);
            addAuditLog($pdo, 'حذف باقة', "الباقة: {$pkg['title']}", $_SESSION['store_user']['username']);
        }
        jsonResponse(['success' => true, 'message' => 'تم حذف الباقة']);
    }

    // ============ تعديل مستخدم ============
    if ($action === 'edit_user') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $username = $_POST['username'] ?? '';
        $name = $_POST['name'] ?? '';
        $phone = $_POST['phone'] ?? '';
        $newPassword = $_POST['new_password'] ?? '';

        $stmt = $pdo->prepare("UPDATE users SET name = ?, phone = ? WHERE username = ?");
        $stmt->execute([$name, $phone, $username]);

        if (!empty($newPassword)) {
            $stmt = $pdo->prepare("UPDATE users SET password = ? WHERE username = ?");
            $stmt->execute([encryptPassword($newPassword), $username]);
        }
        addAuditLog($pdo, 'تعديل مستخدم', "المستخدم: $username", $_SESSION['store_user']['username']);
        jsonResponse(['success' => true, 'message' => 'تم تحديث بيانات المشترك']);
    }

    // ============ شحن/خصم رصيد عن طريق رقم الهاتف ============
    if ($action === 'modify_balance_by_phone') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $phone = $_POST['phone'] ?? '';
        $amount = floatval($_POST['amount'] ?? 0);
        $type = $_POST['type'] ?? 'charge';

        $stmt = $pdo->prepare("SELECT username FROM users WHERE phone = ?");
        $stmt->execute([$phone]);
        $user = $stmt->fetch();
        
        if (!$user) {
            jsonResponse(['success' => false, 'message' => 'لم يتم العثور على مستخدم بهذا الرقم'], 404);
        }
        
        $username = $user['username'];
        $stmt = $pdo->prepare("UPDATE users SET balance = balance + ? WHERE username = ?");
        $stmt->execute([$type === 'charge' ? $amount : -$amount, $username]);

        $txnAmount = $type === 'charge' ? $amount : -$amount;
        $stmt = $pdo->prepare("INSERT INTO transactions (user_identifier, type, title, description, amount, transaction_date) VALUES (?, 'system', ?, 'شحن عبر رقم الهاتف', ?, date('now'))");
        $stmt->execute([$username, $type === 'charge' ? 'شحن إداري' : 'خصم إداري', $txnAmount]);

        $invoiceNo = 'ADM-' . date('YmdHis') . '-' . random_int(100, 999);
        addAuditLog($pdo, $type === 'charge' ? 'شحن رصيد' : 'خصم رصيد', "رقم الهاتف: $phone | مبلغ: $amount", $_SESSION['store_user']['username']);
        jsonResponse([
            'success' => true,
            'message' => "تم تحديث رصيد المستخدم $username",
            'invoice' => [
                'invoice_no' => $invoiceNo,
                'user_identifier' => $username,
                'phone' => $phone,
                'type' => $type,
                'amount' => abs($txnAmount),
                'date' => date('Y-m-d H:i:s'),
                'admin_name' => $_SESSION['store_user']['name'] ?? $_SESSION['store_user']['username'],
                'admin_username' => $_SESSION['store_user']['username']
            ]
        ]);
    }

    // ============ شحن/خصم رصيد (طريقة قديمة) ============
    if ($action === 'modify_balance') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $username = $_POST['username'] ?? '';
        $amount = floatval($_POST['amount'] ?? 0);
        $type = $_POST['type'] ?? 'charge';

        $stmt = $pdo->prepare("UPDATE users SET balance = balance + ? WHERE username = ?");
        $stmt->execute([$type === 'charge' ? $amount : -$amount, $username]);

        $txnAmount = $type === 'charge' ? $amount : -$amount;
        $stmt = $pdo->prepare("INSERT INTO transactions (user_identifier, type, title, description, amount, transaction_date) VALUES (?, 'system', ?, 'بواسطة المشرف', ?, date('now'))");
        $stmt->execute([$username, $type === 'charge' ? 'شحن إداري' : 'خصم إداري', $txnAmount]);

        $invoiceNo = 'ADM-' . date('YmdHis') . '-' . random_int(100, 999);
        addAuditLog($pdo, $type === 'charge' ? 'شحن رصيد' : 'خصم رصيد', "المستخدم: $username | مبلغ: $amount", $_SESSION['store_user']['username']);
        jsonResponse([
            'success' => true,
            'message' => 'تم تحديث الرصيد',
            'invoice' => [
                'invoice_no' => $invoiceNo,
                'user_identifier' => $username,
                'type' => $type,
                'amount' => abs($txnAmount),
                'date' => date('Y-m-d H:i:s'),
                'admin_name' => $_SESSION['store_user']['name'] ?? $_SESSION['store_user']['username'],
                'admin_username' => $_SESSION['store_user']['username']
            ]
        ]);
    }

    // ============ فحص بطاقة ============
    if ($action === 'inspect_card') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $cardUsername = trim($_POST['card_username'] ?? '');
        
        $stmt = $pdo->prepare("SELECT * FROM cards WHERE username = ?");
        $stmt->execute([$cardUsername]);
        $card = $stmt->fetch();
        
        if (!$card) {
            jsonResponse(['success' => false, 'message' => 'البطاقة غير موجودة'], 404);
        }
        
        // جلب الأجهزة المتصلة
        $stmt = $pdo->prepare("SELECT * FROM devices_info WHERE card_username = ? ORDER BY last_seen DESC");
        $stmt->execute([$cardUsername]);
        $devices = $stmt->fetchAll();
        
        // جلب الجلسات النشطة
        $stmt = $pdo->prepare("SELECT * FROM device_sessions WHERE card_username = ? AND is_active = 1");
        $stmt->execute([$cardUsername]);
        $activeSessions = $stmt->fetchAll();
        
        jsonResponse([
            'success' => true,
            'card' => $card,
            'devices' => $devices,
            'active_sessions' => $activeSessions
        ]);
    }

    // ============ تغيير كلمة مرور بطاقة ============
    if ($action === 'change_card_password') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $cardUsername = trim($_POST['card_username'] ?? '');
        $newPassword = trim($_POST['new_password'] ?? '');
        
        if (empty($newPassword)) {
            jsonResponse(['success' => false, 'message' => 'الرجاء إدخال كلمة مرور جديدة'], 400);
        }
        
        // تحديث كلمة المرور مباشرة دون الرجوع للقديمة
        $stmt = $pdo->prepare("UPDATE cards SET password = ? WHERE username = ?");
        $stmt->execute([$newPassword, $cardUsername]);
        
        addAuditLog($pdo, 'تغيير كلمة مرور بطاقة', "البطاقة: $cardUsername", $_SESSION['store_user']['username']);
        jsonResponse(['success' => true, 'message' => 'تم تغيير كلمة مرور البطاقة بنجاح']);
    }

    // ============ إنشاء بطاقة مخصصة ============
    if ($action === 'create_custom_card') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $username = trim($_POST['username'] ?? '');
        $password = trim($_POST['password'] ?? '');
        $hours = intval($_POST['hours'] ?? 0);
        $minutes = intval($_POST['minutes'] ?? 0);
        $serial = trim($_POST['serial'] ?? '');
        $allDevices = intval($_POST['all_devices'] ?? 0);
        $speedMbps = intval($_POST['speed_mbps'] ?? 0);

        if (empty($username) || empty($password)) {
            jsonResponse(['success' => false, 'message' => 'الرجاء إدخال اسم المستخدم وكلمة المرور'], 400);
        }
        if ($hours === 0 && $minutes === 0) {
            jsonResponse(['success' => false, 'message' => 'الرجاء تحديد مدة صلاحية'], 400);
        }
        if (empty($serial)) $serial = generateSerial();

        $validity = trim(($hours > 0 ? $hours . ' ساعة ' : '') . ($minutes > 0 ? $minutes . ' دقيقة' : ''));

        // تحقق من وجود اسم المستخدم مسبقاً
        $checkStmt = $pdo->prepare("SELECT COUNT(*) FROM cards WHERE username = ?");
        $checkStmt->execute([$username]);
        if ((int)$checkStmt->fetchColumn() > 0) {
            jsonResponse(['success' => false, 'message' => 'اسم المستخدم موجود مسبقاً في المخزن، الرجاء اختيار اسم مختلف'], 409);
        }

        try {
            $stmt = $pdo->prepare("INSERT INTO cards (username, password, package_title, status, owner, serial, validity_text, price, expiry_hours, expiry_minutes, custom_created, all_devices, speed_mbps) VALUES (?, ?, 'بطاقة مخصصة', 'متاح', 'admin', ?, ?, 0, ?, ?, 1, ?, ?)");
            $stmt->execute([$username, $password, $serial, $validity, $hours, $minutes, $allDevices, $speedMbps]);
        } catch (PDOException $e) {
            if (strpos($e->getMessage(), 'UNIQUE') !== false) {
                jsonResponse(['success' => false, 'message' => 'اسم المستخدم أو الرقم التسلسلي موجود مسبقاً، الرجاء تغييره'], 409);
            }
            jsonResponse(['success' => false, 'message' => 'حدث خطأ في قاعدة البيانات: ' . $e->getMessage()], 500);
        }

        addAuditLog($pdo, 'إنشاء بطاقة مخصصة', "يوزر: $username | جميع الأجهزة: " . ($allDevices ? 'نعم' : 'لا') . " | السرعة: {$speedMbps} ميجا", $_SESSION['store_user']['username']);
        jsonResponse(['success' => true, 'message' => 'تم إنشاء البطاقة المخصصة', 'card' => ['username' => $username, 'password' => $password, 'validity' => $validity, 'serial' => $serial, 'all_devices' => $allDevices, 'speed_mbps' => $speedMbps]]);
    }

    // ============ اعتماد كروت المطبعة ============
    if ($action === 'save_printed_cards') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $cards = json_decode($_POST['cards'] ?? '[]', true);
        if (empty($cards)) {
            jsonResponse(['success' => false, 'message' => 'لا توجد كروت'], 400);
        }

        $stmt = $pdo->prepare("INSERT INTO cards (username, password, package_title, status, owner, serial, validity_text, price, expiry_hours, expiry_minutes, speed_mbps, custom_created) VALUES (?, ?, ?, 'متاح', 'admin', ?, ?, ?, ?, ?, ?, 0)");
        $count = 0;
        foreach ($cards as $card) {
            $stmt->execute([$card['user'], $card['pass'], $card['tag'] ?? 'بطاقة', $card['serial'] ?? generateSerial(), $card['valid'] ?? '', floatval($card['price'] ?? 0), intval($card['expiryHours'] ?? 24), intval($card['expiryMinutes'] ?? 0), intval($card['speedMbps'] ?? 0)]);
            $count++;
        }
        addAuditLog($pdo, 'اعتماد كروت مطبعة', "العدد: $count", $_SESSION['store_user']['username']);
        jsonResponse(['success' => true, 'message' => "تم اعتماد $count كرت في المخزن"]);
    }

    // ============ تغيير كلمة المرور ============
    if ($action === 'change_password') {
        if (!isset($_SESSION['store_user'])) {
            jsonResponse(['success' => false, 'message' => 'يرجى تسجيل الدخول'], 401);
        }
        $oldPass = $_POST['old_password'] ?? '';
        $newPass = $_POST['new_password'] ?? '';
        $user = $_SESSION['store_user'];

        if (!verifyPassword($oldPass, $user['password'])) {
            jsonResponse(['success' => false, 'message' => 'كلمة المرور الحالية غير صحيحة'], 400);
        }
        if (strlen($newPass) < 3) {
            jsonResponse(['success' => false, 'message' => 'كلمة المرور قصيرة جداً'], 400);
        }

        $stmt = $pdo->prepare("UPDATE users SET password = ? WHERE id = ?");
        $stmt->execute([encryptPassword($newPass), $user['id']]);
        addAuditLog($pdo, 'تغيير كلمة المرور', "المستخدم: {$user['username']}", $user['username']);
        jsonResponse(['success' => true, 'message' => 'تم تغيير كلمة المرور بنجاح']);
    }

    // ============ تحديث صلاحية مستخدم ============
    if ($action === 'toggle_user_role') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $username = trim($_POST['username'] ?? '');
        $desiredRole = $_POST['role'] ?? '';
        if (empty($username)) {
            jsonResponse(['success' => false, 'message' => 'الرجاء إدخال اسم المستخدم'], 400);
        }
        if ($desiredRole === 'admin' || $desiredRole === 'user') {
            $stmt = $pdo->prepare("UPDATE users SET role = ? WHERE username = ?");
            $stmt->execute([$desiredRole, $username]);
            $message = $desiredRole === 'admin' ? 'تم منح المستخدم صلاحية المدير' : 'تم سحب صلاحية المدير من المستخدم';
        } else {
            $stmt = $pdo->prepare("UPDATE users SET role = CASE WHEN role='admin' THEN 'user' ELSE 'admin' END WHERE username = ?");
            $stmt->execute([$username]);
            $message = 'تم تغيير الصلاحية';
        }
        $stmt = $pdo->prepare("SELECT role FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $updated = $stmt->fetch();
        addAuditLog($pdo, 'تغيير صلاحية', "المستخدم: $username | الصلاحية: " . ($updated['role'] ?? 'غير معروف'), $_SESSION['store_user']['username']);
        jsonResponse(['success' => true, 'message' => $message, 'role' => $updated['role'] ?? null]);
    }

    // ============ تسجيل خروج المتجر ============
    if ($action === 'logout_store') {
        if (isset($_SESSION['store_user'])) {
            addAuditLog($pdo, 'تسجيل خروج', "المستخدم: {$_SESSION['store_user']['name']}", $_SESSION['store_user']['username']);
        }
        unset($_SESSION['store_user']);
        session_destroy();
        jsonResponse(['success' => true, 'message' => 'تم تسجيل الخروج']);
    }

    // ============ استعادة كلمة المرور ============
    if ($action === 'forgot_password') {
        $username = trim(strtolower($_POST['username'] ?? ''));
        $phone = trim($_POST['phone'] ?? '');

        $stmt = $pdo->prepare("SELECT * FROM users WHERE username = ? AND phone = ?");
        $stmt->execute([$username, $phone]);
        $user = $stmt->fetch();

        if (!$user) {
            jsonResponse(['success' => false, 'message' => 'لم يتم العثور على حساب مطابق'], 404);
        }

        $newPass = strval(rand(1000, 9999));
        $stmt = $pdo->prepare("UPDATE users SET password = ? WHERE id = ?");
        $stmt->execute([encryptPassword($newPass), $user['id']]);
        addAuditLog($pdo, 'استعادة كلمة مرور', "المستخدم: $username", $username);
        jsonResponse(['success' => true, 'message' => 'تم استعادة كلمة المرور', 'new_password' => $newPass]);
    }

    // ============ حظر/فك حظر مستخدم ============
    if ($action === 'toggle_user_block') {
        if (!isset($_SESSION['store_user']) || $_SESSION['store_user']['role'] !== 'admin') {
            jsonResponse(['success' => false, 'message' => 'غير مصرح'], 403);
        }
        $username = trim($_POST['username'] ?? '');
        $block = intval($_POST['block'] ?? 0);

        if (empty($username)) {
            jsonResponse(['success' => false, 'message' => 'الرجاء تحديد المستخدم'], 400);
        }

        // لا تسمح بحظر المدير الرئيسي
        if ($username === 'admin' && $block === 1) {
            jsonResponse(['success' => false, 'message' => 'لا يمكن حظر حساب المدير الرئيسي'], 403);
        }

        $stmt = $pdo->prepare("UPDATE users SET is_blocked = ? WHERE username = ?");
        $stmt->execute([$block, $username]);

        $actionLabel = $block ? 'حظر مستخدم' : 'فك حظر مستخدم';
        addAuditLog($pdo, $actionLabel, "المستخدم: $username", $_SESSION['store_user']['username']);
        jsonResponse([
            'success' => true,
            'message' => $block ? "تم حظر المستخدم $username بنجاح" : "تم فك حظر المستخدم $username بنجاح",
            'blocked' => $block
        ]);
    }

    jsonResponse(['success' => false, 'message' => 'إجراء غير معروف'], 404);
}

// ============ الحصول على الإعدادات للعرض ============
$hotspotTitle = getSetting($pdo, 'hotspot_title', 'Sohaib Net');
$hotspotSubtitle = getSetting($pdo, 'hotspot_subtitle', 'شبكة Sohaib Net لخدمات الإنترنت');
