$ownerName = getSetting($pdo, 'owner_name', 'م.صهيب قديح');
$hotspotBgUrl = getSetting($pdo, 'hotspot_bg_url', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=1200&q=80');
$storeBgUrl = getSetting($pdo, 'store_bg_url', 'https://images.unsplash.com/photo-1557683316-973673baf926?w=1200&q=80');
$darkMode = getSetting($pdo, 'dark_mode', 'false') === 'true';
$marqueeText = getSetting($pdo, 'marquee_text', '🌟 أهلاً بك في صهيب نت | أفضل خدمة إنترنت بأسعار منافسة | للدعم الفني: 0599038268 🌟');
$welcomeMessage = getSetting($pdo, 'welcome_message', ' أهلاً وسهلاً بك في شبكة صهيب نت! نتمنى لك تجربة إنترنت ممتعة واستخدم الشبكة بما يرضي الله.');

$storeLoggedIn = isset($_SESSION['store_user']);
$storeUser = $_SESSION['store_user'] ?? null;

?>
