        /* === Modern premium refresh overrides === */
        :root{
            --primary: #1e3799;
            --primary-2: #0f172a;
            --accent: #8b5cf6;
            --accent-2: #06b6d4;
            --success: #10b981;
            --warning: #f59e0b;
            --danger: #ef4444;
        }
        html { scroll-behavior: smooth; }
        body{
            font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Tahoma, sans-serif;
            background:
                radial-gradient(circle at top, rgba(99,102,241,.18), transparent 28%),
                radial-gradient(circle at bottom left, rgba(14,165,233,.12), transparent 30%),
                linear-gradient(180deg, #f8fbff 0%, #edf4ff 100%);
        }
        .dark-mode body{
            background:
                radial-gradient(circle at top, rgba(59,130,246,.15), transparent 28%),
                radial-gradient(circle at bottom left, rgba(139,92,246,.12), transparent 30%),
                linear-gradient(180deg, #020617 0%, #0f172a 100%);
        }
        .phone{
            max-width: 540px;
            box-shadow: 0 30px 80px rgba(15,23,42,.18);
            border-left: 1px solid rgba(255,255,255,.5);
            border-right: 1px solid rgba(255,255,255,.5);
        }
        .page{
            opacity: 0;
            transform: translateY(16px) scale(.985);
            animation: pageIn .42s cubic-bezier(.2,.8,.2,1) forwards;
            will-change: transform, opacity;
        }
        .page.active{
            display: block;
            opacity: 1;
            transform: none;
        }
        @keyframes pageIn{
            from{ opacity:0; transform: translateY(18px) scale(.985); }
            to{ opacity:1; transform: translateY(0) scale(1); }
        }
        .header{
            font-size: 24px;
            letter-spacing: -.4px;
            padding: 2px 0 6px;
        }
        .section-title{
            background: linear-gradient(135deg, rgba(30,55,153,.08), rgba(15,23,42,.04));
            border: 1px solid rgba(148,163,184,.18);
            box-shadow: 0 10px 26px rgba(15,23,42,.05);
        }
        .balance, .auth-content-area, .security-box, .status-detail-card, .status-hero, .card-item{
            box-shadow: 0 18px 50px rgba(15,23,42,.08);
        }
        .balance{
            position: relative;
            overflow: hidden;
            background: linear-gradient(135deg, #1e3799 0%, #0f172a 100%);
        }
        .balance::after{
            content:"";
            position:absolute;
            inset:-40% -20% auto auto;
            width:180px;
            height:180px;
            background: radial-gradient(circle, rgba(255,255,255,.22), transparent 68%);
            pointer-events:none;
        }
        .btn, .btn-sm, .feature-btn, .nav-item, .item, .tx-item{
            transition: transform .2s ease, box-shadow .2s ease, background .2s ease, border-color .2s ease, color .2s ease, opacity .2s ease;
        }
        .btn:hover, .btn-sm:hover, .feature-btn:hover, .nav-item:hover{
            transform: translateY(-2px);
        }
        .feature-btn{
            background: rgba(255,255,255,.72);
            border: 1px solid rgba(255,255,255,.72);
            backdrop-filter: blur(16px);
            box-shadow: 0 12px 30px rgba(15,23,42,.08);
        }
        .dark-mode .feature-btn{
            background: rgba(15,23,42,.72);
            border-color: rgba(71,85,105,.4);
        }
        .admin-stat-card{
            border-radius: 24px;
            box-shadow: 0 18px 35px rgba(15,23,42,.12);
            backdrop-filter: blur(10px);
        }
        .nav{
            height: 76px;
            background: rgba(255,255,255,.9);
            border: 1px solid rgba(255,255,255,.72);
            box-shadow: 0 16px 40px rgba(15,23,42,.12);
        }
        .dark-mode .nav{
            background: rgba(15,23,42,.9);
            border-color: rgba(71,85,105,.55);
        }
        .nav-item{
            width: 25%;
            border-radius: 18px;
            height: 54px;
            justify-content: center;
            gap: 2px;
            color: var(--muted);
        }
        .nav-item i{
            font-size: 19px;
            margin-bottom: 1px;
        }
        .nav-item.active{
            color: var(--primary);
            background: linear-gradient(145deg, rgba(30,55,153,.12), rgba(15,23,42,.04));
            box-shadow: inset 0 1px 0 rgba(255,255,255,.5), 0 10px 22px rgba(30,55,153,.12);
        }
        .dark-mode .nav-item.active{
            color: #93c5fd;
            background: linear-gradient(145deg, rgba(59,130,246,.16), rgba(15,23,42,.05));
        }
        .nav-item.admin-nav{
            color: #c084fc;
        }
        .nav-item.admin-nav.active{
            color: #9333ea;
            background: linear-gradient(145deg, rgba(147,51,234,.16), rgba(15,23,42,.05));
        }
        .brand-hero, .store-brand-hero{
            display:flex;
            align-items:center;
            gap:12px;
            padding:14px 16px;
            border-radius:24px;
            background: linear-gradient(135deg, rgba(15,23,42,.94), rgba(30,55,153,.78));
            color:#fff;
            box-shadow: 0 18px 45px rgba(15,23,42,.22);
            margin: 8px 0 14px;
            position: relative;
            overflow:hidden;
        }
        .brand-hero::before, .store-brand-hero::before{
