        .dark-mode .store-top-banner p, .dark-mode .brand-copy .muted-line{
            color: #cbd5e1;
        }
        .page .store-footer{
            border-radius: 18px;
            background: linear-gradient(135deg, rgba(15,23,42,.05), rgba(30,55,153,.06));
            border: 1px solid rgba(148,163,184,.18);
            box-shadow: 0 8px 24px rgba(15,23,42,.04);
