        :root {
            --sn-gold: #f5c451;
            --sn-gold-2: #d69e2e;
            --sn-ink: #08111f;
            --sn-card: rgba(255,255,255,.82);
            --sn-border: rgba(255,255,255,.14);
        }
        html { scroll-behavior: smooth; }
        body { background: radial-gradient(circle at top, #eef4ff 0%, #dfe8f9 45%, #cfd8ee 100%); }
        .phone { box-shadow: 0 24px 80px rgba(15,23,42,.18); }
        .page { transition: opacity .28s ease, transform .28s ease; }
        .page:not(.active) { transform: translateY(8px) scale(.992); }
        .nav { backdrop-filter: blur(18px); border-top: 1px solid rgba(148,163,184,.15); }
        .nav-item { letter-spacing: .1px; }
        .nav-item i { font-size: 19px; }
        .nav-item.active { text-shadow: 0 6px 18px rgba(30,55,153,.22); }
        .nav-item.admin-nav.active { text-shadow: 0 6px 18px rgba(126,34,206,.28); }
        .feature-icon-circle { box-shadow: 0 14px 30px rgba(15,23,42,.08); border: 1px solid rgba(255,255,255,.7); }
        .feature-btn span { font-size: 11px; }
        .feature-btn:hover .feature-icon-circle,
        .feature-btn:active .feature-icon-circle { transform: translateY(-2px) scale(1.03); }
        .brand-hero, .store-brand-hero {
            position: relative;
            overflow: hidden;
            border-radius: 28px;
            padding: 16px 18px;
            background: linear-gradient(135deg, rgba(15,23,42,.92), rgba(30,41,59,.72));
            border: 1px solid rgba(255,255,255,.12);
            box-shadow: 0 18px 45px rgba(15,23,42,.2);
            color: #fff;
            display: flex;
            align-items: center;
            gap: 14px;
        }
        .brand-hero::after, .store-brand-hero::after {
            content: "";
            position: absolute;
            inset: 0;
            background: linear-gradient(120deg, rgba(255,255,255,.16), transparent 35%, transparent 65%, rgba(245,196,81,.12));
            pointer-events: none;
        }
        .brand-mark {
            width: 68px;
            height: 68px;
            border-radius: 22px;
            background: linear-gradient(145deg, #fff, #dbe7ff);
            color: #0f172a;
            box-shadow: inset 0 1px 0 rgba(255,255,255,.95), 0 16px 30px rgba(0,0,0,.18);
            position: relative;
            overflow: hidden;
        }
        .brand-mark::before {
            content: "";
            position: absolute;
            inset: 0;
            background: radial-gradient(circle at 30% 25%, rgba(245,196,81,.5), transparent 40%);
        }
        .brand-mark span { font-size: 22px; font-weight: 900; letter-spacing: 1.2px; }
        .brand-copy h2 { font-size: 24px; line-height: 1; }
        .brand-copy p { font-size: 11px; letter-spacing: .28em; opacity: .92; }
        .brand-copy .muted-line { font-size: 12px; opacity: .86; }
        .auth-content-area { border: 1px solid rgba(255,255,255,.34); box-shadow: 0 18px 52px rgba(15,23,42,.14); }
        .auth-content-area::before {
            content: "";
            position: absolute;
            inset: 0;
            background: linear-gradient(180deg, rgba(255,255,255,.06), transparent 30%, rgba(255,255,255,.04));
            pointer-events: none;
            border-radius: 24px;
        }
        #hotspot-pg, #login-pg {
            position: relative;
            background-attachment: fixed;
        }
        #hotspot-pg::before, #login-pg::before {
            content: "";
            position: absolute;
            inset: 0;
            background: linear-gradient(180deg, rgba(4,10,24,.52), rgba(4,10,24,.28));
            pointer-events: none;
        }
        #hotspot-pg .auth-page-container, #login-pg .auth-page-container, #status-pg .auth-page-container {
            position: relative;
            z-index: 1;
        }
        .input-gp input, .input-gp select {
            border-radius: 16px;
            background: rgba(255,255,255,.92);
            border: 1px solid rgba(148,163,184,.22);
            box-shadow: inset 0 1px 0 rgba(255,255,255,.6);
        }
        .input-gp input:focus, .input-gp select:focus {
            border-color: #3b82f6;
            box-shadow: 0 0 0 4px rgba(59,130,246,.12);
        }
        .btn, .btn-sm, .btn-xs { border-radius: 16px; }
        .pdf-page {
            page-break-after: always;
            position: relative;
            width: 210mm;
            min-height: 297mm;
            padding: 8mm;
            overflow: hidden;
        }
        .printable-card {
            border-radius: 4mm;
            overflow: hidden;
            position: relative;
        }
        .print-card-badge {
            position: absolute;
            top: 2.2mm;
            left: 2.2mm;
            padding: .9mm 1.8mm;
            border-radius: 999px;
            background: rgba(245,196,81,.16);
            border: 1px solid rgba(245,196,81,.32);
            color: #f5c451;
            font-size: 4.2px;
            font-weight: 800;
            letter-spacing: .18em;
        }
        .print-card-note {
            margin-top: 1mm;
            font-size: 4.7px;
            opacity: .92;
            text-align: center;
            line-height: 1.4;
            min-height: 7mm;
        }
        .print-controls-pill {
            display:flex; gap:8px; flex-wrap:wrap; font-size:12px; color:#cbd5e1;
            margin: 6px 0 14px;
        }
        .print-controls-pill span {
            background: rgba(15,23,42,.55);
            border: 1px solid rgba(255,255,255,.12);
            padding: 8px 10px;
            border-radius: 999px;
        }
        .grid-2-1 { display:grid; grid-template-columns: 1fr 1fr; gap:12px; }
        .modern-section-title { display:flex; align-items:center; gap:10px; }
        .modern-section-title i { width: 34px; height: 34px; border-radius: 12px; display:grid; place-items:center; background: linear-gradient(135deg, rgba(59,130,246,.14), rgba(168,85,247,.16)); }
        .status-hero h2 { font-size: 22px; }
        .status-badge-active { box-shadow: 0 8px 24px rgba(16,185,129,.18); }
        @media (max-width: 480px) {
            .brand-hero, .store-brand-hero { padding: 14px; border-radius: 24px; }
            .brand-mark { width: 60px; height: 60px; border-radius: 20px; }
            .brand-copy h2 { font-size: 21px; }
            .features-grid { grid-template-columns: repeat(5, minmax(0,1fr)); }
            .grid-2-1 { grid-template-columns: 1fr; }
        }

    
        .store-top-banner { display: none !important; }
        .user-note-box {
            margin-top: 14px;
            background: linear-gradient(135deg, rgba(59,130,246,0.12), rgba(15,23,42,0.08));
            border: 1px solid rgba(59,130,246,0.18);
            border-radius: 20px;
            padding: 14px 16px;
            display: flex;
            gap: 12px;
            align-items: flex-start;
            box-shadow: 0 10px 24px rgba(15,23,42,0.06);
        }
        .user-note-box i {
            width: 42px;
            height: 42px;
            min-width: 42px;
            border-radius: 14px;
            background: linear-gradient(135deg, #1e3799, #0f172a);
            color: #fff;
            display: flex;
            align-items: center;
            justify-content: center;
            box-shadow: 0 8px 18px rgba(30,55,153,0.25);
        }
        .user-note-box strong { display:block; font-size: 14px; color: var(--dark); margin-bottom: 4px; }
        .user-note-box p { font-size: 12px; color: var(--muted); line-height: 1.7; }

        .feature-btn {
            background: linear-gradient(180deg, rgba(255,255,255,0.98), rgba(248,250,252,0.96));
            border: 1px solid rgba(148,163,184,0.18);
            border-radius: 22px;
            padding: 16px 10px;
            box-shadow: 0 12px 24px rgba(15,23,42,0.06);
            backdrop-filter: blur(10px);
        }
        .feature-btn span { display:block; margin-top: 8px; font-size: 12px; font-weight: 800; color: var(--dark); }
        .feature-icon-circle {
            width: 54px;
            height: 54px;
            border-radius: 18px;
            display:flex;
            align-items:center;
            justify-content:center;
            color:#fff;
            margin:0 auto;
            box-shadow: 0 10px 18px rgba(15,23,42,0.18);
        }
        .f-shop { background: linear-gradient(135deg, #0ea5e9, #1e3799); }
        .f-cards { background: linear-gradient(135deg, #8b5cf6, #6d28d9); }
        .f-send { background: linear-gradient(135deg, #10b981, #047857); }
        .f-invoice { background: linear-gradient(135deg, #f59e0b, #d97706); }
        .f-charge { background: linear-gradient(135deg, #ec4899, #be185d); }

        .item.card-modern {
            align-items: stretch;
            gap: 14px;
            border-radius: 24px;
            padding: 16px;
            background: linear-gradient(180deg, rgba(255,255,255,0.98), rgba(248,250,252,0.98));
            box-shadow: 0 14px 28px rgba(15,23,42,0.07);
        }
        .mycard-status {
            display: inline-flex;
            margin-top: 10px;
            padding: 7px 12px;
            border-radius: 999px;
            font-size: 11px;
            font-weight: 900;
        }
        .mycard-status.used { background: rgba(16,185,129,0.12); color: #047857; }
        .mycard-status.ok { background: rgba(59,130,246,0.12); color: #1d4ed8; }
        .mycard-status.expired { background: rgba(230,57,70,0.12); color: #b91c1c; }
        .mycard-detail, .mycard-meta {
            margin-top: 8px;
            font-size: 11px;
            line-height: 1.7;
            color: var(--muted);
        }

        .admin-floating-dock {
            display: grid;
            grid-template-columns: repeat(4, minmax(0,1fr));
            gap: 8px;
            position: fixed;
            left: 12px;
            right: 12px;
            bottom: 92px;
            z-index: 30;
            margin: 0 auto;
            max-width: 760px;
            padding: 12px;
            border-radius: 24px;
            background: rgba(255,255,255,0.94);
            backdrop-filter: blur(16px);
            border: 1px solid rgba(126,34,206,0.12);
            box-shadow: 0 14px 30px rgba(15,23,42,0.10);
        }
        .admin-dock-btn {
            border: none;
            border-radius: 18px;
            padding: 12px 8px;
            background: linear-gradient(180deg, #ffffff, #f8fafc);
            box-shadow: 0 8px 16px rgba(15,23,42,0.06);
            color: #0f172a;
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 8px;
            font-size: 11px;
            font-weight: 800;
        }
        .admin-dock-btn i { font-size: 18px; color: #7e22ce; }
        .admin-dock-btn:active { transform: scale(0.97); }
        .admin-dock-btn.active { background: linear-gradient(135deg, #1e3799, #0f172a); color: #fff; }
        .admin-dock-btn.active i { color: #fbbf24; }

        .nav {
            height: 74px;
            border: 1px solid rgba(255,255,255,0.6);
            background: rgba(255,255,255,0.9);
        }
        .nav-item {
            flex: 1;
            margin: 0 4px;
            height: 54px;
            border-radius: 18px;
            display:flex;
            flex-direction: column;
            justify-content:center;
            align-items:center;
            gap: 4px;
            font-size: 11px;
            font-weight: 800;
            color: #64748b;
            transition: 0.2s ease;
        }
        .nav-item i { font-size: 18px; }
        .nav-item.active {
            background: linear-gradient(135deg, #1e3799, #0f172a);
            color: #fff;
            box-shadow: 0 10px 20px rgba(30,55,153,0.24);
        }
        .dark-mode .admin-floating-dock { background: rgba(15,23,42,0.88); border-color: rgba(148,163,184,0.18); }
        .dark-mode .admin-dock-btn { background: linear-gradient(180deg, #1e293b, #0f172a); color: #e2e8f0; }
        .dark-mode .feature-btn { background: linear-gradient(180deg, rgba(30,41,59,0.98), rgba(15,23,42,0.96)); border-color: rgba(71,85,105,0.35); }
        .dark-mode .feature-btn span, .dark-mode .user-note-box strong, .dark-mode .mycard-meta, .dark-mode .mycard-detail { color: #e2e8f0; }

        /* ========== GLASSMORPHISM UPGRADE V22 ========== */
        .glass-card {
            background: rgba(255,255,255,0.75);
            backdrop-filter: blur(16px);
            -webkit-backdrop-filter: blur(16px);
            border: 1px solid rgba(255,255,255,0.5);
            border-radius: 20px;
            box-shadow: 0 8px 32px rgba(0,0,0,0.08), inset 0 1px 0 rgba(255,255,255,0.6);
        }
        .dark-mode .glass-card {
            background: rgba(30,41,59,0.75);
            border-color: rgba(71,85,105,0.4);
        }

        /* ========== AI CHAT BUTTON ========== */
        #ai-chat-fab {
            position: fixed;
            bottom: 90px;
            left: 16px;
            width: 52px; height: 52px;
            background: linear-gradient(135deg, #7c3aed, #4f46e5);
            border-radius: 50%;
            display: flex; align-items: center; justify-content: center;
            color: #fff; font-size: 22px;
            box-shadow: 0 4px 20px rgba(124,58,237,0.4);
            cursor: pointer;
            z-index: 9990;
            border: none;
            transition: transform 0.2s, box-shadow 0.2s;
            animation: pulse-chat 2.5s ease-in-out infinite;
        }
        #ai-chat-fab:hover { transform: scale(1.1); box-shadow: 0 6px 24px rgba(124,58,237,0.6); }
        @keyframes pulse-chat {
            0%,100% { box-shadow: 0 4px 20px rgba(124,58,237,0.4); }
            50% { box-shadow: 0 4px 30px rgba(124,58,237,0.7); }
        }

        /* ========== CHAT PANEL ========== */
        #chat-panel {
            position: fixed;
            bottom: 155px; left: 10px; right: 10px;
            max-width: 480px;
            height: 420px;
            background: var(--glass);
            backdrop-filter: blur(20px);
            -webkit-backdrop-filter: blur(20px);
            border: 1px solid var(--glass-border);
            border-radius: 24px;
            box-shadow: 0 20px 60px rgba(0,0,0,0.15);
            display: none;
            flex-direction: column;
            z-index: 9999;
            overflow: hidden;
            margin: 0 auto;
        }
        @media (min-width: 768px) {
            #chat-panel { left: auto; right: 10px; width: 380px; }
        }
        #chat-panel.open { display: flex; }
        .chat-header {
            padding: 14px 16px;
            background: linear-gradient(135deg, #7c3aed, #4f46e5);
            color: #fff;
            font-weight: 700;
            font-size: 14px;
            display: flex; align-items: center; gap: 8px;
            border-radius: 24px 24px 0 0;
        }
        .chat-header .close-chat { margin-right: auto; cursor: pointer; font-size: 18px; opacity: 0.8; }
        .chat-messages {
            flex: 1;
            overflow-y: auto;
            padding: 12px;
            display: flex;
            flex-direction: column;
            gap: 10px;
        }
        .chat-msg { max-width: 85%; padding: 10px 14px; border-radius: 16px; font-size: 13px; line-height: 1.5; }
        .chat-msg.bot { background: #f0f4ff; color: #1e293b; border-radius: 16px 16px 16px 4px; align-self: flex-start; }
        .chat-msg.user { background: linear-gradient(135deg, #7c3aed, #4f46e5); color: #fff; border-radius: 16px 16px 4px 16px; align-self: flex-end; }
        .dark-mode .chat-msg.bot { background: #1e293b; color: #e2e8f0; }
        .chat-input-row {
            padding: 10px 12px;
            display: flex; gap: 8px;
            border-top: 1px solid var(--glass-border);
        }
        .chat-input-row input {
            flex: 1; padding: 10px 14px; border: 1.5px solid #e2e8f0; border-radius: 12px;
            font-size: 13px; font-family: 'Cairo', sans-serif;
            background: #f8fafc; outline: none;
        }
        .dark-mode .chat-input-row input { background: #1e293b; border-color: #334155; color: #e2e8f0; }
        .chat-send-btn {
            width: 40px; height: 40px;
            background: linear-gradient(135deg, #7c3aed, #4f46e5);
            border-radius: 12px; border: none; color: #fff; font-size: 16px;
            cursor: pointer; display: flex; align-items: center; justify-content: center;
            flex-shrink: 0;
        }
        .chat-quick-btns { padding: 0 12px 8px; display: flex; gap: 6px; flex-wrap: wrap; }
        .chat-quick-btn {
            padding: 5px 10px; border-radius: 20px; font-size: 11px; font-weight: 700;
            border: 1.5px solid #7c3aed; color: #7c3aed; background: transparent;
            cursor: pointer; white-space: nowrap; font-family: 'Cairo', sans-serif;
        }
        .chat-quick-btn:hover { background: #7c3aed; color: #fff; }
        .chat-typing { padding: 8px 14px; font-size: 12px; color: var(--muted); font-style: italic; }

        /* ========== NETWORK MONITOR BADGE ========== */
        .net-status-badge {
            display: inline-flex; align-items: center; gap: 6px;
            padding: 6px 12px; border-radius: 20px; font-size: 12px; font-weight: 700;
        }
        .net-status-badge.online { background: #dcfce7; color: #15803d; }
        .net-status-badge.offline { background: #fee2e2; color: #dc2626; }
        .net-dot { width: 8px; height: 8px; border-radius: 50%; }
        .net-dot.green { background: #22c55e; animation: blink-green 1.5s infinite; }
        .net-dot.red { background: #ef4444; }
        @keyframes blink-green {
            0%,100% { opacity: 1; } 50% { opacity: 0.3; }
        }

        /* ========== SPLASH SCREEN ========== */
        #splash-screen {
            position: fixed; inset: 0; z-index: 99999;
            background: linear-gradient(135deg, #0f172a 0%, #1e3799 50%, #0f172a 100%);
            display: flex; flex-direction: column;
            align-items: center; justify-content: center;
            transition: opacity 0.6s ease, transform 0.6s ease;
        }
        #splash-screen.hide { opacity: 0; transform: scale(1.05); pointer-events: none; }
        .splash-logo { width: 90px; height: 90px; background: rgba(255,255,255,0.1); border-radius: 26px;
            display: flex; align-items: center; justify-content: center; font-size: 40px;
            border: 2px solid rgba(212,168,67,0.6); margin-bottom: 20px;
            animation: floatUp 2s ease-in-out infinite; }
        .splash-title { color: #fff; font-size: 28px; font-weight: 800; margin-bottom: 6px; }
        .splash-sub { color: rgba(255,255,255,0.6); font-size: 13px; letter-spacing: 2px; text-transform: uppercase; }
        .splash-bar { width: 200px; height: 4px; background: rgba(255,255,255,0.2); border-radius: 2px; margin-top: 30px; overflow: hidden; }
        .splash-fill { height: 100%; background: linear-gradient(90deg, #d4a843, #fbbf24); border-radius: 2px; animation: fill-bar 1.8s ease-out forwards; }
        @keyframes fill-bar { from { width: 0; } to { width: 100%; } }

        /* ========== TICKET SYSTEM ========== */
        .ticket-item {
            background: var(--glass);
            border: 1px solid var(--glass-border);
            border-radius: 16px;
            padding: 14px;
            margin-bottom: 10px;
        }
        .ticket-status { display: inline-flex; padding: 3px 10px; border-radius: 20px; font-size: 11px; font-weight: 700; }
        .ticket-status.open { background: #fef3c7; color: #d97706; }
        .ticket-status.closed { background: #dcfce7; color: #15803d; }
        .ticket-status.pending { background: #e0e7ff; color: #4338ca; }

        /* ========== ANIMATED ICONS ========== */
        .icon-bounce { animation: icon-bounce 1s ease-in-out infinite; }
        @keyframes icon-bounce { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-4px); } }
        .icon-spin { animation: icon-spin 2s linear infinite; }
        @keyframes icon-spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .icon-pulse { animation: icon-pulse 1.5s ease-in-out infinite; }
        @keyframes icon-pulse { 0%,100% { transform: scale(1); } 50% { transform: scale(1.2); } }

        /* ========== BOTTOM NAV IMPROVEMENTS ========== */
        .bottom-nav-pro {
            position: fixed; bottom: 0; left: 0; right: 0; max-width: 500px; margin: 0 auto;
            height: 68px;
