    <script>
        // ============ متغيرات عامة ============
        const DEVICE_ID = 'dev_' + Math.random().toString(36).substr(2, 9) + '_' + Date.now();
        let storeUserData = <?php echo $storeLoggedIn ? json_encode($storeUser, JSON_UNESCAPED_UNICODE) : 'null'; ?>;
        let contactPhone = '<?php echo htmlspecialchars($contactPhone); ?>';
        let darkMode = <?php echo $darkMode ? 'true' : 'false'; ?>;
        let activeCardUsername = null;
        let currentDeviceName = '';
        let currentMacAddress = '';
        let globalCardsArray = [];
        let allPackages = [];
        let allMyCards = [];
        let allTransactions = [];
        let adminData = null;
        let redirectTimer = null;
        let lastConnectedCard = null;

        // ============ الحصول على معلومات الجهاز ============
        function getDeviceInfo() {
            const ua = navigator.userAgent;
            let deviceName = 'جهاز غير معروف';
            if (/Android/i.test(ua)) {
                deviceName = 'جهاز أندرويد';
                const match = ua.match(/Android\s([0-9.]+)/);
                if (match) deviceName += ' ' + match[1];
            } else if (/iPhone|iPad|iPod/i.test(ua)) {
                deviceName = 'جهاز iOS';
                const match = ua.match(/OS\s([0-9_]+)/);
                if (match) deviceName += ' ' + match[1].replace(/_/g, '.');
            } else if (/Windows/i.test(ua)) deviceName = 'كمبيوتر ويندوز';
            else if (/Mac/i.test(ua)) deviceName = 'كمبيوتر ماك';
            else if (/Linux/i.test(ua)) deviceName = 'لينكس';

            currentDeviceName = deviceName;
            currentMacAddress = 'MAC-' + Math.random().toString(16).substr(2, 6).toUpperCase();
            return { deviceName, macAddress: currentMacAddress };
        }
        getDeviceInfo();

        // ============ التهيئة ============
        if (darkMode) document.body.classList.add('dark-mode');

        function updateLiveClocks() {
            const now = new Date();
            const timeStr = now.toLocaleTimeString('ar-SA', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true });
            const cornerClock = document.getElementById('live-clock-corner');
            if (cornerClock) cornerClock.innerText = timeStr;
        }
        updateLiveClocks();
        setInterval(updateLiveClocks, 1000);

        // ============ دوال AJAX ============
        async function apiCall(action, data = {}) {
            try {
                const formData = new FormData();
                formData.append('action', action);
                for (const [k, v] of Object.entries(data)) {
                    formData.append(k, v);
                }
                const response = await fetch(window.location.href, {
                    method: 'POST',
                    body: formData
                });
                return await response.json();
            } catch (e) {
                console.error('API Error:', e);
                return { success: false, message: 'خطأ في الاتصال بالخادم' };
            }
        }

        // ============ إخفاء/إظهار رسائل الخطأ ============
        function showFieldError(fieldId, message) {
            const el = document.getElementById(fieldId);
            if (el) {
                el.innerText = message;
                el.classList.add('show');
            }
        }

        function clearFieldErrors() {
            document.querySelectorAll('.error-message').forEach(el => {
                el.classList.remove('show');
                el.innerText = '';
            });
        }

        function setHotspotInlineError(message) {
            const area = document.getElementById('session-warning-area');
            if (area) {
                area.innerHTML = message ? `<div class="session-warning" style="margin-bottom:12px;">${message}</div>` : '';
            }
        }

        function copyTextToClipboard(text, successMessage = '✅ تم النسخ') {
            const done = () => Swal.fire({ title: successMessage, timer: 1400, showConfirmButton: false, toast: true, position: 'bottom' });
            // Try modern clipboard API first
            if (navigator.clipboard && typeof navigator.clipboard.writeText === 'function') {
                navigator.clipboard.writeText(text).then(done).catch(() => fallbackCopyTextToClipboard(text, successMessage));
            } else {
                fallbackCopyTextToClipboard(text, successMessage);
            }
        }

        // ============ التنقل ============
        function syncBottomNav() {
            const homeItem = document.getElementById('n-home');
            const homeIcon = homeItem ? homeItem.querySelector('i') : null;
            const homeLabel = document.getElementById('n-home-label');
            const isAdmin = !!(storeUserData && storeUserData.role === 'admin');

            if (homeItem) {
                if (isAdmin) {
                    homeItem.setAttribute('onclick', "goNav('admin-pg')");
                    homeItem.classList.add('admin-nav');
                } else {
                    homeItem.setAttribute('onclick', "goNav('home-pg')");
                    homeItem.classList.remove('admin-nav');
                }
            }
            if (homeIcon) homeIcon.className = isAdmin ? 'fa-solid fa-users-gear' : 'fa-solid fa-house-chimney-window';
            if (homeLabel) homeLabel.innerText = isAdmin ? 'إدارة المستخدمين' : 'الرئيسية';

            const adminNav = document.getElementById('n-admin');
            if (adminNav) adminNav.style.display = isAdmin ? 'flex' : 'none';
        }

        function showAuth(pageId) {
            clearFieldErrors();
            const nav = document.getElementById('app-nav');
            if (nav) nav.classList.remove('active');
            document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
            const page = document.getElementById(pageId);
            if (page) {
                requestAnimationFrame(() => page.classList.add('active'));
            }
            syncBottomNav();
            updateLiveClocks();
            if (pageId === 'hotspot-pg') {
                const warn = document.getElementById('session-warning-area');
                if (warn) warn.innerHTML = '';
                setInlineFormError('hotspot-form-error', '');
                restoreRememberedAuth('hotspot-pg');
            }
            if (pageId === 'login-pg') {
                setInlineFormError('login-form-error', '');
                restoreRememberedAuth('login-pg');
            }
        }

        function goNav(pageId) {
            clearFieldErrors();
            document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
            const page = document.getElementById(pageId);
            if (page) {
                requestAnimationFrame(() => page.classList.add('active'));
            }

            document.querySelectorAll('.nav-item').forEach(i => i.classList.remove('active'));
            const navId = 'n-' + pageId.split('-')[0];
            const navItem = document.getElementById(navId);
            if (navItem) navItem.classList.add('active');

            const nav = document.getElementById('app-nav');
            if (nav) nav.classList.add('active');
            syncBottomNav();

            if (pageId === 'mycards-pg') loadMyCards();
            if (pageId === 'home-pg') {
                if (storeUserData && storeUserData.role === 'admin') {
                    goNav('admin-pg');
                    return;
                }
                toggleDashboardView('shop');
            }
            if (pageId === 'admin-pg') loadAdminData();
            if (pageId === 'profile-pg') loadProfileData();
        }

        // ============ الاتصال بالإنترنت ============
        async function connectWifi() {
            clearFieldErrors();
            setHotspotInlineError('');
            setInlineFormError('hotspot-form-error', '');
            const u = document.getElementById('wifi-user').value.trim();
            const p = document.getElementById('wifi-pass').value.trim();
            const remember = !!document.getElementById('hotspot-remember')?.checked;

            if (!u || !p) {
                setInlineFormError('hotspot-form-error', 'الرجاء إدخال اسم المستخدم وكلمة المرور');
                return;
            }

            setHotspotInlineError('<i class="fa-solid fa-spinner fa-spin"></i> جاري التحقق من بيانات البطاقة...');
            const result = await apiCall('connect_wifi', {
                username: u,
                password: p,
                device_id: DEVICE_ID,
                device_name: currentDeviceName,
                mac_address: currentMacAddress
            });

            setHotspotInlineError('');

            if (result.success) {
                saveRememberedAuth('hotspot-pg', u, p, remember);
                activeCardUsername = u;
                currentDeviceName = result.device_name || currentDeviceName;
                currentMacAddress = result.mac_address || currentMacAddress;
                showConnectSuccessPage(result.card);
            } else {
                const msg = result.message || 'تعذر الاتصال';
                setInlineFormError('hotspot-form-error', msg);
            }
        }

        function showConnectSuccessPage(card) {
            lastConnectedCard = card;
            document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
            document.getElementById('connect-success-pg').classList.add('active');
            document.getElementById('app-nav').classList.remove('active');
            document.getElementById('conn-pkg').innerText = card.package_title || 'بطاقة مخصصة';
            document.getElementById('conn-user').innerText = card.username;
            document.getElementById('conn-valid').innerText = card.validity_text || `${card.expiry_hours||0} ساعة ${card.expiry_minutes||0} دقيقة`;
            if (redirectTimer) { clearInterval(redirectTimer); redirectTimer = null; }
        }

        function showStatusFromSuccess() {
            if (lastConnectedCard) showStatusPage(lastConnectedCard);
        }

        function showStatusPage(card) {
            if (redirectTimer) { clearInterval(redirectTimer); redirectTimer = null; }
            document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
            document.getElementById('status-pg').classList.add('active');
            document.getElementById('app-nav').classList.remove('active');
            updateLiveClocks();

            document.getElementById('status-user').innerText = card.username;
            document.getElementById('status-pkg').innerText = card.package_title || 'مخصصة';
            document.getElementById('status-device-name').innerText = currentDeviceName;
            document.getElementById('status-pkg-title').innerText = card.package_title || 'بطاقة مخصصة';
            const expired = card.activated_at && (card.expiry_hours > 0 || card.expiry_minutes > 0) && new Date() > new Date(new Date(card.activated_at).getTime() + (card.expiry_hours * 3600 + card.expiry_minutes * 60) * 1000);
            document.getElementById('status-badge-el').className = expired ? 'status-badge-expired' : 'status-badge-active';
            document.getElementById('status-badge-el').innerText = expired ? '🔴 منتهي' : '🟢 متصل ونشط';

            const activatedAt = card.activated_at ? new Date(card.activated_at) : null;
            if (activatedAt && (card.expiry_hours > 0 || card.expiry_minutes > 0)) {
                const expiryMs = activatedAt.getTime() + (card.expiry_hours * 3600 + card.expiry_minutes * 60) * 1000;
                const remainingMs = expiryMs - Date.now();
                if (remainingMs > 0) {
                    const hrs = Math.floor(remainingMs / 3600000);
                    const mins = Math.floor((remainingMs % 3600000) / 60000);
                    document.getElementById('status-remaining').innerText = `${hrs} ساعة ${mins} دقيقة`;
                    document.getElementById('status-badge-el').className = 'status-badge-active';
                    document.getElementById('status-badge-el').innerText = '🟢 متصل ونشط';
                } else {
                    document.getElementById('status-remaining').innerText = 'منتهية';
                    document.getElementById('status-badge-el').className = 'status-badge-expired';
                    document.getElementById('status-badge-el').innerText = '🔴 منتهية الصلاحية';
                }
            } else {
                document.getElementById('status-remaining').innerText = 'غير محددة';
            }
        }

        async function logoutFromStatus() {
            if (activeCardUsername) {
                await apiCall('disconnect_wifi', { username: activeCardUsername, device_id: DEVICE_ID });
                activeCardUsername = null;
            }
            Swal.fire({ title: '👋 تم تسجيل الدخول بنجاح، نتمنى لكم تجربة استخدام ممتعة', html: '<p>تم إنهاء الجلسة بنجاح.</p>', icon: 'success', timer: 2000, showConfirmButton: false }).then(() => { showAuth('hotspot-pg'); });
        }

        // ============ نسخ الرابط من صفحة المستخدم ============
        function copyHotspotLink() {
            const url = window.location.origin + window.location.pathname;
            copyTextToClipboard(url, '✅ تم نسخ الرابط');
        }

        function fallbackCopyTextToClipboard(text, successMessage = '✅ تم النسخ') {
            const textArea = document.createElement('textarea');
            textArea.value = text;
            textArea.style.position = 'fixed';
            textArea.style.top = '0';
            textArea.style.left = '0';
            textArea.style.opacity = '0';
            document.body.appendChild(textArea);
            textArea.focus();
            textArea.select();
            try {
                document.execCommand('copy');
                Swal.fire({ title: successMessage, timer: 1400, showConfirmButton: false, toast: true, position: 'bottom' });
            } catch (err) {
                Swal.fire('نسخ النص', text, 'info');
            }
            document.body.removeChild(textArea);
        }

        const REMEMBER_STORAGE_KEYS = {
            hotspot: 'sohaibnet_remember_hotspot',
            store: 'sohaibnet_remember_store'
        };

        function safeSetLocalStorage(key, value) {
            try { localStorage.setItem(key, value); } catch (e) {}
        }

        function safeGetLocalStorage(key) {
            try { return localStorage.getItem(key); } catch (e) { return null; }
        }

        function safeRemoveLocalStorage(key) {
            try { localStorage.removeItem(key); } catch (e) {}
        }

        function setInlineFormError(areaId, message) {
            const el = document.getElementById(areaId);
            if (!el) return;
            if (message) {
                el.textContent = message;
                el.classList.add('show');
            } else {
                el.textContent = '';
                el.classList.remove('show');
            }
        }

        function restoreRememberedAuth(pageId) {
            if (pageId === 'hotspot-pg') {
                const user = safeGetLocalStorage(REMEMBER_STORAGE_KEYS.hotspot + '_user') || '';
                const pass = safeGetLocalStorage(REMEMBER_STORAGE_KEYS.hotspot + '_pass') || '';
                const remember = safeGetLocalStorage(REMEMBER_STORAGE_KEYS.hotspot + '_enabled') === '1';
                const uEl = document.getElementById('wifi-user');
                const pEl = document.getElementById('wifi-pass');
                const cEl = document.getElementById('hotspot-remember');
                if (uEl) uEl.value = user;
                if (pEl) pEl.value = pass;
                if (cEl) cEl.checked = remember;
            }
            if (pageId === 'login-pg') {
                const user = safeGetLocalStorage(REMEMBER_STORAGE_KEYS.store + '_user') || '';
                const pass = safeGetLocalStorage(REMEMBER_STORAGE_KEYS.store + '_pass') || '';
                const remember = safeGetLocalStorage(REMEMBER_STORAGE_KEYS.store + '_enabled') === '1';
                const uEl = document.getElementById('l-user');
                const pEl = document.getElementById('l-pass');
                const cEl = document.getElementById('login-remember');
                if (uEl) uEl.value = user;
                if (pEl) pEl.value = pass;
                if (cEl) cEl.checked = remember;
            }
        }

        function saveRememberedAuth(pageId, user, pass, remember) {
            const prefix = pageId === 'hotspot-pg' ? REMEMBER_STORAGE_KEYS.hotspot : REMEMBER_STORAGE_KEYS.store;
            if (remember) {
                safeSetLocalStorage(prefix + '_enabled', '1');
                safeSetLocalStorage(prefix + '_user', user || '');
                safeSetLocalStorage(prefix + '_pass', pass || '');
            } else {
                safeRemoveLocalStorage(prefix + '_enabled');
                safeRemoveLocalStorage(prefix + '_user');
                safeRemoveLocalStorage(prefix + '_pass');
            }
        }

        // ============ المتجر ============

        async function loginStore() {
            clearFieldErrors();
            setInlineFormError('login-form-error', '');
            const user = document.getElementById('l-user').value.trim().toLowerCase();
            const pass = document.getElementById('l-pass').value.trim();
            const remember = !!document.getElementById('login-remember')?.checked;

            if (!user || !pass) {
                setInlineFormError('login-form-error', 'الرجاء إدخال اسم المستخدم وكلمة المرور');
                return;
            }

            Swal.fire({ title: '🔄 جاري الدخول...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
            const result = await apiCall('login_store', { username: user, password: pass });
            Swal.close();
            if (result.success) {
                saveRememberedAuth('login-pg', user, pass, remember);
                storeUserData = result.user;
                initStoreUI();
            } else {
                setInlineFormError('login-form-error', result.message || 'تعذر تسجيل الدخول');
            }
        }

        async function registerStore() {
            const n = document.getElementById('r-name').value.trim();
            const u = document.getElementById('r-user').value.trim().toLowerCase();
            const ph = document.getElementById('r-phone').value.trim();
            const p = document.getElementById('r-pass').value.trim();
            const pc = document.getElementById('r-pass-confirm').value.trim();
            if (!n || !u || !ph || !p || !pc) { Swal.fire('تنبيه ⚠️', 'الرجاء ملء جميع الحقول', 'warning'); return; }
            if (p !== pc) { Swal.fire('خطأ ❌', 'كلمتا المرور غير متطابقتين', 'error'); return; }
            if (p.length < 3) { Swal.fire('خطأ ❌', 'كلمة المرور قصيرة جداً', 'error'); return; }
            Swal.fire({ title: '🔄 جاري إنشاء الحساب...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
            const result = await apiCall('register_store', { name: n, username: u, phone: ph, password: p, password_confirm: pc });
            Swal.close();
            if (result.success) {
                Swal.fire('تم بنجاح ✅', result.message, 'success');
                showAuth('login-pg');
            } else {
                Swal.fire('خطأ ❌', result.message, 'error');
            }
        }

        async function confirmBuyCard(packageId, price, title) {
            if (!packageId) return;

            const result = await Swal.fire({
                title: '🛒 تأكيد الشراء',
                html: `<div style="text-align:right;">
                    <p style="margin-bottom:8px;">هل تريد شراء <b>${title || 'هذه الباقة'}</b>؟</p>
                    <p style="margin:0;color:#0f172a;">السعر: <b style="color:#10b981;">${Number(price || 0).toFixed(2)} ₪</b></p>
                </div>`,
                icon: 'question',
                showCancelButton: true,
                confirmButtonText: 'نعم، اشترِ',
                cancelButtonText: 'إلغاء'
            });

            if (!result.isConfirmed) return;

            Swal.fire({ title: '🔄 جاري تنفيذ الشراء...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
            const response = await apiCall('buy_card', { package_id: packageId });
            Swal.close();

            if (!response.success) {
                Swal.fire('خطأ', response.message || 'تعذر إتمام عملية الشراء', 'error');
                return;
            }

            if (response.new_balance !== undefined && storeUserData) {
                storeUserData.balance = response.new_balance;
                const balEl = document.getElementById('u-balance-txt');
                if (balEl) balEl.innerText = parseFloat(response.new_balance).toFixed(2) + ' ₪';
            }

            const card = response.card || {};
            await Swal.fire({
                title: '✅ تم الشراء بنجاح',
                html: `<div style="text-align:right;">
                    <p><b>يوزر البطاقة:</b> ${card.username || '-'}</p>
                    <p><b>المرور:</b> ${card.password || '-'}</p>
                    <p><b>الباقة:</b> ${card.package_title || title || '-'}</p>
                </div>`,
                icon: 'success',
                confirmButtonText: 'حسنًا'
            });

            if (typeof loadMyCards === 'function') loadMyCards();
        }

        async function forgotPassword() {
            Swal.fire({ title: '🔑 استعادة كلمة المرور', html: '<p>أدخل اسم المستخدم ورقم الهاتف المسجل</p><input id="fp-user" class="swal2-input" placeholder="اسم المستخدم" style="text-align:right;"><input id="fp-phone" class="swal2-input" placeholder="رقم الهاتف" style="text-align:right;">', showCancelButton: true, confirmButtonText: 'استعادة', cancelButtonText: 'إلغاء', preConfirm: () => { const u = document.getElementById('fp-user').value.trim().toLowerCase(), ph = document.getElementById('fp-phone').value.trim(); if (!u || !ph) { Swal.showValidationMessage('الرجاء ملء جميع الحقول'); return false; } return { username: u, phone: ph }; } }).then(async r => {
                if (r.isConfirmed) {
                    Swal.fire({ title: '🔄 جاري البحث...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
                    const result = await apiCall('forgot_password', r.value);
                    Swal.close();
                    if (result.success) {
                        Swal.fire({ title: '✅ تم استعادة كلمة المرور', html: `<p>كلمة المرور الجديدة: <b style="color:#3b5998;font-size:20px;">${result.new_password}</b></p>`, icon: 'success' });
                    } else {
                        Swal.fire('خطأ ❌', result.message, 'error');
                    }
                }
            });
        }

        function initStoreUI() {
            if (!storeUserData) { showAuth('login-pg'); return; }
            document.getElementById('app-nav').classList.add('active');
            syncBottomNav();
            if (storeUserData.role === 'admin') {
                document.getElementById('n-mycards').style.display = 'none';
                document.getElementById('user-exclusive-view').style.display = 'none';
                goNav('admin-pg');
            } else {
                document.getElementById('n-mycards').style.display = 'flex';
                document.getElementById('user-exclusive-view').style.display = 'block';
                document.getElementById('u-balance-txt').innerText = parseFloat(storeUserData.balance).toFixed(2) + ' ₪';
                document.getElementById('user-display').innerText = 'المشترك: ' + storeUserData.name;
                goNav('home-pg');
            }
            loadProfileData();
        }

        async function logoutStore() {
            await apiCall('logout_store');
            storeUserData = null;
            syncBottomNav();
            document.getElementById('app-nav').classList.remove('active');
            showAuth('login-pg');
        }

        function loadProfileData() {
            if (!storeUserData) return;
            document.getElementById('p-name').innerText = storeUserData.name || '-';
            document.getElementById('p-user').innerText = storeUserData.username || '-';
            document.getElementById('p-phone').innerText = storeUserData.phone || '-';
        }

        async function updateUserPassword() {
            const old = document.getElementById('p-old-pass').value.trim();
            const nw = document.getElementById('p-new-pass').value.trim();
            if (!old || !nw) { Swal.fire('تنبيه', 'الرجاء إدخال كلمتي المرور', 'warning'); return; }
            if (nw.length < 3) { Swal.fire('خطأ', 'كلمة المرور قصيرة جداً', 'error'); return; }
            const result = await apiCall('change_password', { old_password: old, new_password: nw });
            if (result.success) Swal.fire('تم بنجاح ✅', result.message, 'success');
            else Swal.fire('خطأ ❌', result.message, 'error');
        }

        function toggleDarkMode() {
            darkMode = !darkMode;
            document.body.classList.toggle('dark-mode', darkMode);
            Swal.fire({ title: darkMode ? '🌙 الوضع الليلي مفعل' : '☀️ الوضع النهاري مفعل', timer: 1500, showConfirmButton: false, toast: true, position: 'bottom' });
        }

        // ============ عرض كل الحوالات ============
        async function showAllTransactions() {
            if (!storeUserData) return;
            const result = await apiCall('get_store_data');
            if (result.success) {
                allTransactions = result.transactions;
                let html = '<div style="text-align:right;max-height:400px;overflow-y:auto;">';
                html += '<h4 style="text-align:center;margin-bottom:12px;">📄 جميع الحوالات</h4>';
                if (allTransactions.length === 0) {
                    html += '<p style="text-align:center;color:var(--muted);">لا توجد حوالات</p>';
                } else {
                    html += [...allTransactions].reverse().map(t => `
                        <div class="tx-item" style="border-right:4px solid ${t.amount<0?'#e63946':'#2ecc71'};">
                            <div>
                                <div class="tx-title">${t.title}</div>
                                <div class="tx-desc">${t.description} | ${t.transaction_date}</div>
                            </div>
                            <div class="tx-amount ${t.amount<0?'tx-minus':'tx-plus'}">${t.amount<0?'':'+'}${parseFloat(t.amount).toFixed(2)} ₪</div>
                        </div>
                    `).join('');
                }
                html += '</div>';
                Swal.fire({ title: '💰 كشف الحوالات', html: html, confirmButtonText: 'إغلاق', width: '95%' });
            }
        }

        // ============ الإشعارات ============
        async function showNotifications() {
            if (!storeUserData) return;
            const result = await apiCall('get_store_data');
            if (result.success) {
                const recentCards = result.my_cards || [];
                const recentTx = result.transactions || [];
                let html = '<div style="text-align:right;max-height:400px;overflow-y:auto;">';
                html += '<h4 style="text-align:center;margin-bottom:12px;">🔔 الإشعارات</h4>';
                if (recentCards.length > 0) {
                    html += '<p style="font-weight:700;">🎫 آخر البطاقات:</p>';
                    recentCards.slice(0, 5).forEach(c => {
                        html += `<div class="item" style="padding:8px;font-size:12px;">📦 ${c.package_title} | يوزر: ${c.username}</div>`;
                    });
                }
                if (recentTx.length > 0) {
                    html += '<p style="font-weight:700;margin-top:10px;">💵 آخر العمليات:</p>';
                    recentTx.slice(0, 5).forEach(t => {
                        html += `<div class="tx-item" style="padding:8px;font-size:11px;">${t.title}: ${parseFloat(t.amount).toFixed(2)} ₪</div>`;
                    });
                }
                if (recentCards.length === 0 && recentTx.length === 0) {
                    html += '<p style="text-align:center;">لا توجد إشعارات جديدة</p>';
                }
                html += '</div>';
                Swal.fire({ title: '🔔 الإشعارات', html: html, confirmButtonText: 'حسناً', width: '90%' });
            }
        }

        // ============ لوحة المتجر للمستخدمين ============
        async function toggleDashboardView(view) {
            const container = document.getElementById('dashboard-dynamic-content');
            container.innerHTML = '<p style="text-align:center;">🔄 جاري التحميل...</p>';
            const result = await apiCall('get_store_data');
            if (result.success) {
                allPackages = result.packages;
                allMyCards = result.my_cards;
                allTransactions = result.transactions;
                storeUserData = result.user;
                document.getElementById('u-balance-txt').innerText = parseFloat(storeUserData.balance).toFixed(2) + ' ₪';
                document.getElementById('user-display').innerText = 'المشترك: ' + storeUserData.name;
            }
            if (view === 'shop') {
                container.innerHTML = '<h3 style="font-size:15px;margin-bottom:14px;font-weight:800;text-align:right;">🛒 الباقات المتاحة</h3><div id="inner-shop-list"></div>';
                document.getElementById('inner-shop-list').innerHTML = allPackages.map(p => {
                    const oos = p.stock_count == 0;
                    return `<div class="item" style="border-right:4px solid ${p.color};${oos?'opacity:0.6;':''}"><div class="card-details"><div class="item-icon-wrapper" style="background:${p.color};width:48px;height:48px;border-radius:16px;display:flex;align-items:center;justify-content:center;font-size:22px;color:#fff;margin-left:14px;"><i class="fa-solid ${p.icon}"></i></div><div><strong>${p.title}</strong><p style="font-size:11px;color:var(--muted);">${p.description}</p>${oos?'<span class="badge-out-of-stock">⚠️ نفدت الكروت</span>':'<span style="font-size:10px;color:#10b981;">✅ متوفر</span>'}</div></div><div style="text-align:left;"><strong style="color:${p.color};">${p.price} ₪</strong><button class="btn-sm" style="background:${oos?'#94a3b8':p.color};" onclick="confirmBuyCard(${p.id},${p.price},'${p.title.replace(/'/g,"\\'")}')" ${oos?'disabled':''}>${oos?'نفد':'شراء'}</button></div></div>`;
                }).join('');
            } else if (view === 'invoice') {
                container.innerHTML = '<h3 style="font-size:15px;margin-bottom:14px;font-weight:800;text-align:right;">📄 كشف الحساب</h3><div id="tx-history-list"></div>';
                document.getElementById('tx-history-list').innerHTML = allTransactions.length === 0 ? '<p style="text-align:center;color:var(--muted);">لا توجد عمليات</p>' : [...allTransactions].reverse().map(t => `<div class="tx-item"><div style="display:flex;gap:12px;align-items:center;"><div style="width:36px;height:36px;border-radius:10px;background:#f1f5f9;display:flex;align-items:center;justify-content:center;color:${t.amount<0?'#e63946':'#2ecc71'}"><i class="fa-solid ${t.amount<0?'fa-arrow-up':'fa-arrow-down'}"></i></div><div><div class="tx-title">${t.title}</div><div class="tx-desc">${t.description} | ${t.transaction_date}</div></div></div><div class="tx-amount ${t.amount<0?'tx-minus':'tx-plus'}">${t.amount<0?'':'+'}${parseFloat(t.amount).toFixed(2)} ₪</div></div>`).join('');
            }
        }

        async function loadMyCards() {
            const result = await apiCall('get_store_data');
            if (result.success) {
                allMyCards = result.my_cards;
                storeUserData = result.user;
            }
            const list = document.getElementById('my-cards-list');

            const formatCard = (c) => {
                const expiryMs = (Number(c.expiry_hours || 0) * 3600 + Number(c.expiry_minutes || 0) * 60) * 1000;
                const activatedAt = c.activated_at ? new Date(c.activated_at).getTime() : null;
                const expiredAt = activatedAt && expiryMs > 0 ? activatedAt + expiryMs : null;
                const isExpired = !!expiredAt && Date.now() > expiredAt;
                const hideNow = isExpired && Date.now() > (expiredAt + 24 * 3600 * 1000);
                if (hideNow) return null;
                return { isExpired, hideNow };
            };

            const visibleCards = allMyCards.map(c => ({ card: c, meta: formatCard(c) })).filter(x => x.meta !== null);

            if (visibleCards.length === 0) {
                list.innerHTML = '<p style="text-align:center;color:var(--muted);padding:30px;">لا توجد بطاقات مشتراة</p>';
                return;
            }

            list.innerHTML = visibleCards.map(({ card: c, meta }) => {
                return `<div class="item card-modern ${meta.isExpired ? 'expired' : 'ok'}" style="border-right:4px solid ${meta.isExpired ? '#e63946' : '#3b82f6'};">
                    <div style="min-width:0;flex:1;">
                        <span class="badge" style="background:${meta.isExpired ? '#fef2f2' : '#eff6ff'};color:${meta.isExpired ? '#e63946' : '#3b82f6'};">${c.package_title || 'مخصصة'}</span>
                        <strong style="display:block;margin-top:8px;">يوزر: ${c.username}</strong>
                        <div style="font-size:12px;color:var(--muted);margin-top:4px;display:flex;gap:8px;flex-wrap:wrap;">
                            <span>🔑 المرور: ${c.password}</span>
                            ${Number(c.speed_mbps || 0) > 0 ? `<span>⚡ ${c.speed_mbps} ميجا</span>` : ''}
                        </div>
                        <span class="mycard-status ${meta.isExpired ? 'expired' : 'ok'}">${meta.isExpired ? 'منتهية' : 'نشطة'}</span>
                    </div>
                    ${meta.isExpired ? '<div style="display:flex;flex-direction:column;align-items:flex-end;flex-shrink:0;"><span style="font-size:11px;color:#e63946;font-weight:800;">منتهية</span></div>' : `<div style="display:flex;gap:4px;flex-direction:column;align-items:flex-end;flex-shrink:0;">
                        <button class="btn-xs" style="background:#0ea5e9;min-width:90px;" onclick="copyCardUsername(${JSON.stringify(c.username)})"><i class="fa-solid fa-user"></i> نسخ اليوزر</button>
                        <button class="btn-xs" style="background:#8b5cf6;min-width:90px;" onclick="copyCardPassword(${JSON.stringify(c.password)})"><i class="fa-solid fa-key"></i> نسخ المرور</button>
                        <button class="btn-xs" style="background:#64748b;min-width:90px;" onclick="copyCardData(${JSON.stringify(c.username)}, ${JSON.stringify(c.password)})"><i class="fa-solid fa-copy"></i> نسخ الكل</button>
                        <button class="btn-xs" style="background:var(--success);min-width:90px;" onclick="autoLoginWifi(${JSON.stringify(c.username)}, ${JSON.stringify(c.password)})"><i class="fa-solid fa-wifi"></i> دخول تلقائي</button>
                    </div>`}
                </div>`;
            }).join('');
        }

        function copyCardData(u, p) {
            const text = `اسم المستخدم: ${u}
كلمة المرور: ${p}`;
            copyTextToClipboard(text, '✅ تم نسخ معلومات البطاقة كاملة');
        }

        function copyCardUsername(u) {
            copyTextToClipboard(u, '✅ تم نسخ اسم المستخدم');
        }

        function copyCardPassword(p) {
            copyTextToClipboard(p, '✅ تم نسخ كلمة المرور');
        }

        async function openSendBalanceModal() {
            if (!storeUserData) return;
            const { value } = await Swal.fire({
                title: '📤 تحويل رصيد',
                html: `<div style="text-align:right;">
                    <p>💰 رصيدك الحالي: <b style="color:#10b981;">${parseFloat(storeUserData.balance).toFixed(2)} ₪</b></p>
                    <input id="st-phone" class="swal2-input" placeholder="📞 رقم جوال المستلم">
                    <input id="st-amount" type="number" class="swal2-input" placeholder="💵 المبلغ" min="1">
                </div>`,
                showCancelButton: true,
                confirmButtonText: 'متابعة',
                cancelButtonText: 'إلغاء',
                preConfirm: () => {
                    const ph = document.getElementById('st-phone').value.trim();
                    const amt = +document.getElementById('st-amount').value;
                    if (!ph || !amt || amt <= 0) {
                        Swal.showValidationMessage('بيانات غير صحيحة');
                        return false;
                    }
                    return { phone: ph, amount: amt };
                }
            });
            if (!value) return;

            Swal.fire({ title: '🔎 جاري التحقق...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
            const lookup = await apiCall('lookup_user_by_phone', { phone: value.phone });
            Swal.close();
            if (!lookup.success) {
                Swal.fire('خطأ', lookup.message || 'لم يتم العثور على المستلم', 'error');
                return;
            }

            const receiver = lookup.user;
            const confirmResult = await Swal.fire({
                title: '✅ تأكيد التحويل',
                html: `<div style="text-align:right;background:#f8fafc;border-radius:16px;padding:16px;">
                    <div style="display:flex;justify-content:space-between;padding:6px 0;"><span>إلى</span><strong>${receiver.name}</strong></div>
                    <div style="display:flex;justify-content:space-between;padding:6px 0;"><span>رقم الهاتف</span><strong>${receiver.phone}</strong></div>
                    <div style="display:flex;justify-content:space-between;padding:6px 0;"><span>المبلغ</span><strong>${value.amount.toFixed(2)} ₪</strong></div>
                    <div style="display:flex;justify-content:space-between;padding:6px 0;"><span>الرصيد بعد التحويل</span><strong style="color:#10b981;">${(parseFloat(storeUserData.balance) - value.amount).toFixed(2)} ₪</strong></div>
                </div>`,
                icon: 'question',
                showCancelButton: true,
                confirmButtonText: 'تنفيذ التحويل',
                cancelButtonText: 'تراجع'
            });
            if (!confirmResult.isConfirmed) return;

            Swal.fire({ title: '🔄 جاري التحويل...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
            const result = await apiCall('send_balance', value);
            Swal.close();
            if (result.success) {
                storeUserData.balance = result.new_balance;
                document.getElementById('u-balance-txt').innerText = parseFloat(result.new_balance).toFixed(2) + ' ₪';
                lastTransferInvoice = {
                    invoice_no: result.invoice?.invoice_no || `INV-${Date.now()}`,
                    sender_name: result.invoice?.sender_name || storeUserData.name,
                    sender_username: result.invoice?.sender_username || storeUserData.username,
                    receiver_name: result.invoice?.receiver_name || receiver.name,
                    receiver_username: result.invoice?.receiver_username || receiver.username,
                    receiver_phone: result.invoice?.receiver_phone || receiver.phone,
                    amount: result.invoice?.amount || value.amount,
                    date: result.invoice?.date || new Date().toLocaleString('ar-SA')
                };
                Swal.fire({
                    title: '✅ تم التحويل',
                    html: `<div style="text-align:right;">
                        <p>تم التحويل إلى <b>${lastTransferInvoice.receiver_name}</b></p>
                        <p>رقم الفاتورة: <b>${lastTransferInvoice.invoice_no}</b></p>
                    </div>`,
                    icon: 'success',
                    showCancelButton: true,
                    confirmButtonText: 'تنزيل الفاتورة صورة',
                    cancelButtonText: 'إغلاق'
                }).then((r) => {
                    if (r.isConfirmed) downloadTransferInvoiceImage(lastTransferInvoice);
                });
            } else {
                Swal.fire('خطأ ❌', result.message, 'error');
            }
        }

        function openChargeBalanceModal() {
            Swal.fire({ title: '💰 شحن رصيد', html: `<p>رقم الهاتف: <b>${storeUserData?.phone||'غير مسجل'}</b></p><p style="color:#f59e0b;">يرجى التواصل مع الإدارة عبر واتساب لشحن الرصيد</p>`, confirmButtonText: 'فتح واتساب', showCancelButton: true, cancelButtonText: 'إلغاء' }).then(r => { if (r.isConfirmed) openWhatsApp(); });
        }

        async function downloadTransferInvoiceImage(invoice) {
            if (!invoice) return;
            const container = document.createElement('div');
            container.style.position = 'fixed';
            container.style.left = '-10000px';
            container.style.top = '0';
            container.style.width = '900px';
            container.style.padding = '28px';
            container.style.direction = 'rtl';
            container.style.fontFamily = 'Tahoma, Arial, sans-serif';
            container.innerHTML = `
                <div style="border:2px solid #1e3799;border-radius:24px;padding:24px;background:#fff;">
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:18px;">
                        <div>
                            <h2 style="margin:0;color:#1e3799;">فاتورة تحويل رصيد</h2>
                            <div style="color:#64748b;margin-top:6px;">${invoice.invoice_no}</div>
                        </div>
                        <div style="font-size:34px;">🧾</div>
                    </div>
                    <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;font-size:18px;line-height:1.8;">
                        <div style="background:#f8fafc;border-radius:18px;padding:16px;"><b>المرسل:</b><br>${invoice.sender_name}<br>${invoice.sender_username}</div>
                        <div style="background:#f8fafc;border-radius:18px;padding:16px;"><b>المستلم:</b><br>${invoice.receiver_name}<br>${invoice.receiver_phone}</div>
                        <div style="background:#f8fafc;border-radius:18px;padding:16px;"><b>المبلغ:</b><br>${parseFloat(invoice.amount).toFixed(2)} ₪</div>
                        <div style="background:#f8fafc;border-radius:18px;padding:16px;"><b>التاريخ:</b><br>${invoice.date}</div>
                    </div>
                </div>`;
            document.body.appendChild(container);
            try {
                const canvas = await html2canvas(container, { scale: 3, useCORS: true, backgroundColor: '#ffffff', logging: false });
                const blob = await new Promise(resolve => canvas.toBlob(resolve, 'image/png', 1.0));
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `invoice_${invoice.invoice_no || Date.now()}.png`;
                a.click();
                URL.revokeObjectURL(url);
            } finally {
                container.remove();
            }
        }

        let lastTransferInvoice = null;

