        async function loadAdminData() {
            const started = Date.now();
            Swal.fire({ title: '🔄 جاري تحميل البيانات...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
            const result = await apiCall('get_admin_data');
            const remaining = Math.max(0, 2000 - (Date.now() - started));
            setTimeout(() => Swal.close(), remaining);
            if (result.success) {
                adminData = result;
                document.getElementById('stat-users').innerText = result.stats.users;
                document.getElementById('stat-cards').innerText = result.stats.cards;
                document.getElementById('stat-total-money').innerText = parseFloat(result.stats.total_money).toFixed(2) + ' ₪';
                allPackages = result.packages;
                syncPrintPackageOptions(allPackages);
                switchAdminView('store-log');
            } else {
                Swal.fire('خطأ', 'لا يمكن تحميل بيانات الإدارة', 'error');
            }
        }

        function toggleAdminMenu() {
            document.getElementById('admin-dropdown-menu').classList.toggle('active');
        }

        function switchAdminViewFromMenu(sec) {
            switchAdminView(sec);
            document.getElementById('admin-dropdown-menu').classList.remove('active');
        }

        function switchAdminView(sec) {
            ['store-log', 'users', 'packages-manage', 'guess', 'global-settings', 'custom-card', 'audit-log', 'live-sessions', 'hotspot-control', 'card-inspect'].forEach(s => {
                const el = document.getElementById('admin-sec-' + s);
                if (el) el.style.display = s === sec ? 'block' : 'none';
            });
            document.querySelectorAll('.admin-dock-btn').forEach(btn => btn.classList.remove('active'));
            const activeMap = { 'store-log': 1, 'users': 2, 'guess': 3 };
            const activeBtn = document.querySelectorAll('.admin-dock-btn')[activeMap[sec]];
            if (activeBtn) activeBtn.classList.add('active');
            if (!adminData) return;
            if (sec === 'store-log') {
                document.getElementById('admin-global-log-container').innerHTML = adminData.transactions.length === 0 ? '<p style="text-align:center;color:#94a3b8;">لا توجد عمليات</p>' : [...adminData.transactions].reverse().map(t => `<div class="tx-item" style="border-right:4px solid ${t.amount<0?'#e63946':'#2ecc71'};"><div><span class="tx-title">${t.title}</span><span class="tx-desc">${t.user_identifier} | ${t.description}</span></div><div class="tx-amount ${t.amount<0?'tx-minus':'tx-plus'}">${t.amount<0?'':'+'}${parseFloat(t.amount).toFixed(2)} ₪</div></div>`).join('');
            }
            if (sec === 'users') {
                const stockSummary = document.getElementById('admin-available-stock-summary');
                stockSummary.innerHTML = adminData.packages.map(p => {
                    const cnt = adminData.cards.filter(c => c.package_title === p.title && c.status === 'متاح').length;
                    return `<div class="item" style="border-right:4px solid ${p.color};padding:10px;"><strong>${p.title}</strong><span class="badge" style="background:${cnt>0?'#ecfdf5':'#fef2f2'};color:${cnt>0?'#10b981':'#e63946'};">المخزن: ${cnt}</span></div>`;
                }).join('');
                filterAdminUsers();
            }
            if (sec === 'packages-manage') {
                document.getElementById('admin-packages-manage-list').innerHTML = adminData.packages.map(p => `<div class="item" style="border-left:4px solid ${p.color};padding:12px;"><div style="flex:1;"><strong><i class="fa-solid ${p.icon}" style="color:${p.color};"></i> ${p.title}</strong><span style="display:block;font-size:11px;">${p.description}</span><span style="color:${p.color};">${p.price} ₪ | ${p.expiry_hours}س ${p.expiry_minutes}د</span></div><div style="display:flex;gap:4px;flex-direction:column;width:75px;"><button class="btn-xs" style="background:#f59e0b;" onclick="openEditPackageModal(${p.id})">تعديل</button><button class="btn-xs" style="background:#e63946;" onclick="deletePackageAdmin(${p.id})">حذف</button></div></div>`).join('');
            }
            if (sec === 'global-settings') renderGlobalSettings();
            if (sec === 'hotspot-control') renderHotspotControl();
            if (sec === 'audit-log') {
                document.getElementById('audit-log-container').innerHTML = (adminData.audit_logs || []).length === 0 ? '<p style="text-align:center;">لا توجد سجلات</p>' : adminData.audit_logs.map(l => `<div class="tx-item" style="border-right:4px solid #6366f1;font-size:12px;"><div><strong>${l.action}</strong><span style="display:block;font-size:10px;">${l.details}</span></div><span class="badge" style="background:#e0e7ff;color:#4338ca;">${l.user}</span></div>`).join('');
            }
            if (sec === 'guess') generateAction();
        }

                function filterAdminUsers() {
            if (!adminData) return;
            const q = document.getElementById('search-users-input')?.value.trim().toLowerCase() || '';
            document.getElementById('admin-users-list').innerHTML = adminData.users.filter(u => u.name.toLowerCase().includes(q) || u.username.includes(q) || u.phone.includes(q)).map(u => `<div class="item" style="flex-wrap:wrap;border-right:4px solid ${u.is_blocked ? '#ef4444' : '#10b981'};"><div style="flex:1;"><strong>${u.name} (${u.username})</strong><span style="display:block;font-size:11px;">📞 ${u.phone || '-'}</span><span style="display:block;font-size:11px;color:#4f46e5;">💰 ${parseFloat(u.balance).toFixed(2)} ₪</span><span style="display:inline-flex;margin-top:6px;padding:4px 8px;border-radius:999px;font-size:10px;font-weight:800;background:${u.is_blocked ? '#fee2e2' : '#ecfdf5'};color:${u.is_blocked ? '#dc2626' : '#059669'};">${u.is_blocked ? 'محظور' : 'نشط'}</span></div><div style="display:flex;gap:4px;flex-direction:column;width:110px;"><button class="btn-xs" style="background:#3b82f6;" onclick="editUserDataAdmin('${u.username}')">تعديل</button><button class="btn-xs" style="background:#10b981;" onclick="modifyUserBalanceAdmin('${u.username}','charge')">شحن</button><button class="btn-xs" style="background:#e63946;" onclick="modifyUserBalanceAdmin('${u.username}','deduct')">خصم</button><button class="btn-xs" style="background:${u.is_blocked ? '#22c55e' : '#f59e0b'};" onclick="toggleUserBlockAdmin('${u.username}', ${u.is_blocked ? 0 : 1})">${u.is_blocked ? 'فك الحظر' : 'حظر'}</button><button class="btn-xs" style="background:#8b5cf6;" onclick="withdrawUserCardAdmin('${u.username}')">سحب بطاقة</button><button class="btn-xs" style="background:#0ea5e9;" onclick="showUserHistoryAdmin('${u.username}')">سجل</button></div></div>`).join('');
        }

        function renderLiveSessions() {
            const container = document.getElementById('live-sessions-container');
            if (!container) return;
            const sessions = (adminData?.live_sessions || []).filter(s => s.is_active == 1);
            if (!sessions.length) {
                container.innerHTML = '<p style="text-align:center;color:var(--muted);padding:20px;">لا توجد جلسات نشطة حالياً</p>';
                return;
            }
            container.innerHTML = sessions.map(s => `<div class="item" style="flex-wrap:wrap;border-right:4px solid #0ea5e9;"><div style="flex:1;min-width:0;"><strong>${s.card_username}</strong><span style="display:block;font-size:11px;">📱 ${s.device_id}</span><span style="display:block;font-size:11px;">🕒 ${s.last_activity || '-'}</span><span style="display:block;font-size:11px;color:#4f46e5;">📦 ${s.package_title || 'بطاقة'}</span></div><div style="display:flex;gap:6px;align-items:center;"><button class="btn-xs" style="background:#e63946;" onclick="kickSessionAdmin('${s.card_username}', '${s.device_id}')">طرد</button></div></div>`).join('');
        }

