        async function withdrawUserCardAdmin(un) {
            const confirm = await Swal.fire({
                title: '⚠️ سحب البطاقة',
                html: `هل تريد سحب بطاقة المستخدم <b>${un}</b> وإعادتها للمخزن؟`,
                icon: 'warning',
                showCancelButton: true,
                confirmButtonText: 'نعم، سحب البطاقة',
                cancelButtonText: 'إلغاء',
                confirmButtonColor: '#8b5cf6'
            });
            if (!confirm.isConfirmed) return;
            Swal.fire({ title: '⏳ جاري السحب...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
            const result = await apiCall('withdraw_user_card', { username: un });
            Swal.close();
            if (result.success) {
                Swal.fire('تم بنجاح', result.message, 'success');
                loadAdminData();
            } else {
                Swal.fire('خطأ', result.message, 'error');
            }
        }

        async function editUserDataAdmin(un) {
            const u = adminData.users.find(x => x.username === un);
            if (!u) return;
            Swal.fire({ title: 'تعديل بيانات المشترك', html: `<input id="en" class="swal2-input" value="${u.name}" placeholder="الاسم"><input id="ep" class="swal2-input" value="${u.phone}" placeholder="الهاتف"><input id="epa" class="swal2-input" placeholder="كلمة مرور جديدة (اختياري)">`, showCancelButton: true, confirmButtonText: 'حفظ', preConfirm: () => { const n = document.getElementById('en').value.trim(), p = document.getElementById('ep').value.trim(); if (!n || !p) { Swal.showValidationMessage('الاسم والهاتف إلزاميان'); return false; } return { name: n, phone: p, new_password: document.getElementById('epa').value.trim(), username: un }; } }).then(async r => {
