        async function inspectCard() {
            const cardUsername = document.getElementById('inspect-card-user').value.trim();
            if (!cardUsername) { Swal.fire('تنبيه', 'الرجاء إدخال اسم مستخدم البطاقة', 'warning'); return; }
            Swal.fire({ title: '🔎 جاري الفحص...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
            const result = await apiCall('inspect_card', { card_username: cardUsername });
            Swal.close();
            if (result.success) {
                const c = result.card;
                const devices = result.devices || [];
                const sessions = result.active_sessions || [];
                let html = `<div style="text-align:right;background:#f8fafc;border-radius:16px;padding:16px;">`;
                html += `<h4 style="color:#3b5998;">📋 بيانات البطاقة</h4>`;
                html += `<p><b>يوزر:</b> ${c.username} | <b>مرور:</b> ${c.password}</p>`;
                html += `<p><b>الباقة:</b> ${c.package_title} | <b>الحالة:</b> ${c.status}</p>`;
                html += `<p><b>تاريخ التفعيل:</b> ${c.activated_at || 'غير مفعلة'}</p>`;
                html += `<p><b>الساعات:</b> ${c.expiry_hours} | <b>الدقائق:</b> ${c.expiry_minutes}</p>`;
                html += `<p><b>السماح لجميع الأجهزة:</b> ${c.all_devices ? 'نعم' : 'لا'}</p>`;
                html += `<hr style="margin:10px 0;">`;
                html += `<h4 style="color:#f97316;">📱 الأجهزة المتصلة</h4>`;
                if (devices.length === 0) {
                    html += '<p style="color:var(--muted);">لا توجد أجهزة مسجلة</p>';
                } else {
                    devices.forEach(d => {
                        html += `<div class="item" style="padding:8px;font-size:11px;margin-bottom:4px;">
                            <span>📱 ${d.device_name || 'غير معروف'}</span>
                            <span>🔌 ${d.mac_address || '--'}</span>
                            <span>🕐 ${d.last_seen || '--'}</span>
                        </div>`;
                    });
                }
                html += `<hr style="margin:10px 0;">`;
                html += `<h4 style="color:#10b981;">🟢 الجلسات النشطة</h4>`;
                if (sessions.length === 0) {
                    html += '<p style="color:var(--muted);">لا توجد جلسات نشطة</p>';
                } else {
                    sessions.forEach(s => {
                        html += `<p>الجهاز: ${s.device_id} | IP: ${s.ip_address} | آخر نشاط: ${s.last_activity}</p>`;
                    });
                }
                html += `<hr style="margin:10px 0;">`;
                html += `<button class="btn-sm" style="background:#e63946;margin-top:8px;" onclick="changeCardPasswordAdmin('${c.username}')">🔑 تغيير كلمة المرور</button>`;
                html += `</div>`;
                document.getElementById('inspect-card-result').innerHTML = html;
            } else {
                document.getElementById('inspect-card-result').innerHTML = `<p style="color:#e63946;">${result.message}</p>`;
            }
        }

