        async function openBackgroundSettings() {
            Swal.fire({
                title: '🖼️ إعدادات الخلفيات',
                html: `<p>رابط صورة خلفية Hot Spot:</p><input id="bg-hotspot" class="swal2-input" value="${adminData.settings.hotspot_bg_url||''}" placeholder="https://..." style="direction:ltr;"><p>رابط صورة خلفية المتجر:</p><input id="bg-store" class="swal2-input" value="${adminData.settings.store_bg_url||''}" placeholder="https://..." style="direction:ltr;"><p style="margin-top:10px;">أو اختر صورة من جهازك:</p><input type="file" id="bg-file" accept="image/*" style="display:block;margin:10px auto;"><div id="bg-preview" style="margin-top:8px;font-size:12px;color:#64748b;text-align:center;"></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:8px;"><button type="button" class="swal2-styled" id="apply-hotspot-btn">Hot Spot</button><button type="button" class="swal2-styled" id="apply-store-btn">المتجر</button></div><p><small>اختيار الصورة من الهاتف سيحفظها تلقائياً كخلفية جاهزة للعرض.</small></p>`,
                showCancelButton: true,
                confirmButtonText: 'حفظ',
                didOpen: () => {
                    const popup = Swal.getPopup();
                    const fileInput = popup?.querySelector('#bg-file');
                    const preview = popup?.querySelector('#bg-preview');
                    if (popup) {
                        const h = popup.querySelector('#apply-hotspot-btn');
                        const s = popup.querySelector('#apply-store-btn');
                        if (h) h.onclick = () => { popup.dataset.target = 'hotspot'; h.style.filter = 'brightness(1.15)'; if (s) s.style.filter = ''; };
                        if (s) s.onclick = () => { popup.dataset.target = 'store'; s.style.filter = 'brightness(1.15)'; if (h) h.style.filter = ''; };
                    }
                    if (fileInput) {
                        fileInput.addEventListener('change', () => {
                            const file = fileInput.files && fileInput.files[0];
                            if (!file) return;
                            const reader = new FileReader();
                            reader.onload = () => {
                                const dataUrl = reader.result;
                                if (preview) preview.innerHTML = '✅ تم اختيار صورة من الهاتف';
                                const hotspot = document.getElementById('bg-hotspot');
                                const store = document.getElementById('bg-store');
                                const target = popup?.dataset?.target || 'both';
                                if (target === 'hotspot') { if (hotspot) hotspot.value = dataUrl; }
                                else if (target === 'store') { if (store) store.value = dataUrl; }
                                else { if (hotspot) hotspot.value = dataUrl; if (store) store.value = dataUrl; }
                            };
                            reader.readAsDataURL(file);
                        });
                    }
                },
                preConfirm: async () => {
                    const popup = Swal.getPopup();
                    const target = popup?.dataset?.target || 'both';
                    const fileInput = document.getElementById('bg-file');
                    const applyValues = (src) => {
                        if (target === 'hotspot') return { hotspot_bg_url: src, store_bg_url: document.getElementById('bg-store').value.trim() };
                        if (target === 'store') return { hotspot_bg_url: document.getElementById('bg-hotspot').value.trim(), store_bg_url: src };
                        return { hotspot_bg_url: src, store_bg_url: src };
                    };
                    if (fileInput && fileInput.files.length > 0) {
                        const file = fileInput.files[0];
                        const dataUrl = await new Promise(resolve => { const reader = new FileReader(); reader.onload = () => resolve(reader.result); reader.readAsDataURL(file); });
                        return applyValues(dataUrl);
                    }
                    return {
                        hotspot_bg_url: document.getElementById('bg-hotspot').value.trim(),
                        store_bg_url: document.getElementById('bg-store').value.trim()
                    };
                }
            }).then(async r => {
                if (r.isConfirmed) {
                    const result = await apiCall('save_settings', { settings: r.value });
                    if (result.success) Swal.fire('تم بنجاح', 'تم تحديث الخلفيات', 'success').then(() => location.reload());
                    else Swal.fire('خطأ', result.message || 'فشل الحفظ', 'error');
                }
            });
        }

