        function downloadBackup() {
            if (!adminData) return;
            const dataStr = JSON.stringify(adminData, null, 2);
            const blob = new Blob([dataStr], { type: 'application/json' });
            const a = document.createElement('a');
            a.href = URL.createObjectURL(blob);
            a.download = `sohaib_net_backup_${new Date().toISOString().split('T')[0]}.json`;
            a.click();
        }

        // ============ إنشاء كروت وطباعة ============
        function getOptimalGrid(n, cardW, cardH, colsOverride, rowsOverride) {
            if (n <= 1) return { cols: 1, rows: 1 };
            const availW = 210 - 16,
                availH = 297 - 16;
            const maxCols = Math.max(1, Math.floor(availW / (cardW + 3))),
                maxRows = Math.max(1, Math.floor(availH / (cardH + 3)));
            let bestCols = colsOverride > 0 ? Math.min(colsOverride, maxCols) : Math.min(Math.round(Math.sqrt(n * (availW / availH))), maxCols, 10);
            let bestRows = rowsOverride > 0 ? Math.min(rowsOverride, maxRows) : Math.min(Math.ceil(n / bestCols), maxRows, 10);
            if (bestCols < 1) bestCols = 1;
            if (bestRows < 1) bestRows = 1;
            while (bestCols * bestRows < n && bestCols < maxCols) bestCols++;
            while (bestCols * bestRows < n && bestRows < maxRows) bestRows++;
            return { cols: Math.min(bestCols, maxCols), rows: Math.min(bestRows, maxRows) };
        }

