        function syncPrintPackageOptions(packages = []) {
            const select = document.getElementById('cardTag');
            if (!select) return;

            const current = select.value;
            const safePackages = Array.isArray(packages) ? packages : [];
            const seen = new Set();
            const options = [];

            safePackages.forEach(pkg => {
                const title = (pkg && pkg.title) ? String(pkg.title) : '';
                if (!title || seen.has(title)) return;
                seen.add(title);
                options.push(`<option value="${title}">${title}</option>`);
            });

            ['باقة شهرية', 'VIP أسبوعية', '24 ساعة', '10 ساعات'].forEach(title => {
                if (!seen.has(title)) {
                    seen.add(title);
                    options.push(`<option value="${title}">${title}</option>`);
                }
            });

            select.innerHTML = options.join('');
            if (current && seen.has(current)) {
                select.value = current;
            } else if (safePackages[0] && safePackages[0].title) {
                select.value = safePackages[0].title;
            } else {
                select.value = 'باقة شهرية';
            }
        }

        async function autoLoginWifi(u, p) {
            if (!u || !p) return;
            try {
                Swal.fire({ title: '🔄 جاري الاتصال التلقائي...', html: `<p>جاري الاتصال بالبطاقة: <b>${u}</b></p>`, allowOutsideClick: false, didOpen: () => Swal.showLoading() });
                // Direct API call without navigating away
                const deviceId = getOrCreateDeviceId();
                const deviceName = navigator.userAgent.includes('Mobile') ? 'جهاز موبايل' : 'جهاز كمبيوتر';
                const result = await apiCall('connect_wifi', { username: u, password: p, device_id: deviceId, device_name: deviceName, mac_address: '' });
                Swal.close();
                if (result.success) {
                    // Navigate to hotspot page and show connected status
                    showAuth('hotspot-pg');
                    await new Promise(r => setTimeout(r, 150));
                    const userEl = document.getElementById('wifi-user');
