            // Find answer
            let answer = null;
            const ltext = text.toLowerCase();
            for (const [key, val] of Object.entries(chatKnowledge)) {
                if (ltext.includes(key)) { answer = val; break; }
            }
            if (!answer) {
                answer = `عذراً، لم أفهم سؤالك تماماً 🤔. للتواصل المباشر مع الدعم الفني، يرجى الضغط على أيقونة واتساب في الأسفل. يمكنني مساعدتك في: شحن الرصيد، شراء الباقات، مشاكل الاتصال، ونسيان كلمة المرور.`;
            }
            addChatMsg(answer, 'bot');
        }

