                            container.innerHTML = (r.sessions || []).length === 0
                                ? '<p style="text-align:center;color:var(--muted);">لا توجد جلسات نشطة</p>'
                                : r.sessions.map(s => `<div class="item" style="border-right:4px solid #22c55e;"><div style="flex:1;"><strong>${s.card_username}</strong><span style="display:block;font-size:11px;">📡 ${s.ip_address || 'غير معروف'} | ${s.package_title || ''}</span><span style="display:block;font-size:10px;color:var(--muted);">آخر نشاط: ${s.last_activity || ''}</span></div><button class="btn-xs" style="background:#ef4444;" onclick="kickSessionLive('${s.card_username}','${s.device_id}')"><i class="fa-solid fa-ban"></i> طرد</button></div>`).join('');
                        }
                    }
                } catch(e) {}
            }, 10000);
        }

        async function kickSessionLive(username, deviceId) {
            const c = await Swal.fire({ title: 'طرد الجلسة؟', icon: 'warning', showCancelButton: true, confirmButtonText: 'نعم', cancelButtonText: 'لا' });
            if (!c.isConfirmed) return;
            const r = await apiCall('kick_session', { username, device_id: deviceId });
            Swal.fire(r.success ? 'تم' : 'خطأ', r.message, r.success ? 'success' : 'error');
            if (r.success && adminData) loadAdminData();
        }

        // ========== SUPPORT TICKETS (local storage simulation) ==========
        function getTickets() {
            try { return JSON.parse(localStorage.getItem('sohaibnet_tickets') || '[]'); } catch(e) { return []; }
        }
        function saveTickets(tickets) {
            try { localStorage.setItem('sohaibnet_tickets', JSON.stringify(tickets)); } catch(e) {}
        }

        async function openNewTicket() {
            const { value } = await Swal.fire({
                title: '🎫 تذكرة دعم جديدة',
                html: `<div style="text-align:right;">
                    <select id="tkt-cat" class="swal2-input" style="margin-bottom:8px;">
                        <option value="فني">مشكلة فنية</option>
                        <option value="مالي">استفسار مالي</option>
                        <option value="عام">استفسار عام</option>
                    </select>
                    <textarea id="tkt-desc" class="swal2-textarea" placeholder="اشرح مشكلتك بالتفصيل..." style="height:100px;"></textarea>
                </div>`,
                showCancelButton: true,
                confirmButtonText: 'إرسال التذكرة',
                cancelButtonText: 'إلغاء',
                preConfirm: () => {
                    const desc = document.getElementById('tkt-desc').value.trim();
                    if (!desc) { Swal.showValidationMessage('الرجاء كتابة وصف للمشكلة'); return false; }
                    return { category: document.getElementById('tkt-cat').value, description: desc };
                }
            });
            if (!value) return;
            const tickets = getTickets();
            const ticket = {
                id: 'TKT-' + Date.now(),
                category: value.category,
                description: value.description,
                status: 'open',
                created_at: new Date().toLocaleString('ar'),
                user: storeUserData ? storeUserData.name : 'زائر'
            };
            tickets.unshift(ticket);
            saveTickets(tickets);
            Swal.fire({ icon: 'success', title: '✅ تم إرسال التذكرة', html: `رقم تذكرتك: <b>${ticket.id}</b><br>سيتم الرد عليك قريباً.`, timer: 3000 });
        }

        function showMyTickets() {
            const tickets = getTickets();
            if (!storeUserData) return;
            const myTickets = tickets.filter(t => t.user === storeUserData.name);
            const html = myTickets.length === 0
                ? '<p style="color:var(--muted);text-align:center;">لا توجد تذاكر</p>'
                : myTickets.map(t => `<div class="ticket-item">
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
                        <strong style="font-size:12px;">${t.id}</strong>
                        <span class="ticket-status ${t.status}">${t.status === 'open' ? 'مفتوحة' : 'مغلقة'}</span>
                    </div>
                    <div style="font-size:12px;color:var(--muted);">${t.category}</div>
                    <div style="font-size:13px;margin-top:6px;">${t.description.substring(0,80)}${t.description.length > 80 ? '...' : ''}</div>
                    <div style="font-size:10px;color:var(--muted);margin-top:4px;">${t.created_at}</div>
                </div>`).join('');
            Swal.fire({ title: '🎫 تذاكر الدعم الخاصة بك', html: `<div style="text-align:right;max-height:400px;overflow-y:auto;">${html}</div>`, width: '95%', confirmButtonText: 'إغلاق' });
        }

        // Start network monitor when admin page is active
        const _origLoadAdminData = typeof loadAdminData !== 'undefined' ? loadAdminData : null;
        document.addEventListener('DOMContentLoaded', () => {
            // Upgrade nav items to pro style
            setTimeout(() => {
                const navItems = document.querySelectorAll('.nav-item');
                navItems.forEach(item => item.classList.add('nav-item-pro'));
            }, 2000);
        });

    </script>
</body>
</html>